    96→  const [difficulty, setDifficulty] = useState<Difficulty>("Beginner");
    97→  const [description, setDescription] = useState("");
    98→  const [note, setNote] = useState("");
    99→  const [keyTimingMinute, setKeyTimingMinute] = useState("");
   100→  const [keyTimingNote, setKeyTimingNote] = useState("");
   101→  const [heroesInput, setHeroesInput] = useState("");
   102→  const [steps, setSteps] = useState<StepRow[]>([
   103→    { time: "0:00", instruction: "", food: "" },
   104→  ]);
   105→  const [skills, setSkills] = useState<SkillRow[]>([]);
   106→  const [status, setStatus] = useState("");
   107→
   108→  function updateStep(index: number, field: keyof StepRow, value: string) {
   109→    setSteps((prev) =>
   110→      prev.map((s, i) => (i === index ? { ...s, [field]: value } : s)),
   111→    );
   112→  }
   113→
   114→  function addStep() {
   115→    setSteps((prev) => [...prev, { time: "", instruction: "", food: "" }]);
   116→  }
   117→
   118→  function removeStep(index: number) {
   119→    setSteps((prev) => prev.filter((_, i) => i !== index));
   120→  }
   121→
   122→  function updateSkill(index: number, field: keyof SkillRow, value: string) {
   123→    setSkills((prev) =>
   124→      prev.map((s, i) => (i === index ? { ...s, [field]: value } : s)),
   125→    );
   126→  }
   127→
   128→  function addSkill() {
   129→    setSkills((prev) => [
   130→      ...prev,
   131→      { level: String(prev.length + 1), skill: "" },
   132→    ]);
   133→  }
   134→
   135→  function removeSkill(index: number) {
   136→    setSkills((prev) => prev.filter((_, i) => i !== index));
   137→  }
   138→
   139→  function handleSubmit() {
   140→    const keyTimingMin = Number(keyTimingMinute);
   141→    const heroes = heroesInput
   142→      .split(",")
   143→      .map((h) => h.trim())
   144→      .filter(Boolean);
   145→    const build = {
   146→      name,
   147→      race,
   148→      heroes,
   149→      vs: vs || undefined,
   150→      difficulty,
   151→      description,
   152→      note: note || undefined,
   153→      keyTiming:
   154→        keyTimingMinute && keyTimingNote
   155→          ? { minute: keyTimingMin, note: keyTimingNote }
   156→          : undefined,
   157→      steps: steps.map((s, i) => ({
   158→        order: i + 1,
   159→        time: s.time,
   160→        instruction: s.instruction,
   161→        food: s.food,
   162→      })),
   163→      skillOrder:
   164→        skills.length > 0
   165→          ? skills.map((s) => ({
   166→              level: Number(s.level),
   167→              skill: s.skill,
   168→              icon: skillToIconPath(s.skill),
   169→            }))
   170→          : undefined,
   171→    };
   172→
   173→    const count = importBuilds([build]);
   174→    if (count > 0) {
   175→      setStatus("Build order added!");
   176→      setName("");
   177→      setVs("");
   178→      setDescription("");
   179→      setNote("");
   180→      setKeyTimingMinute("");
   181→      setKeyTimingNote("");
   182→      setSteps([{ time: "0:00", instruction: "", food: "" }]);
   183→      setSkills([]);
   184→      setHeroesInput("");
   185→    } else {
   186→      setStatus("Please fill in Name and at least one step with all fields.");
   187→    }
   188→    setTimeout(() => setStatus(""), 4000);
   189→  }
   190→
   191→  return (
   192→    <section className="section-card boi-section">
   193→      <h3>Add Build Order</h3>
   194→
   195→      {/* ── Details ── */}
   196→      <div className="boi-group">
   197→        <div className="boi-field">
   198→          <span className="boi-label">Name</span>
   199→          <EscEditBox
   200→            value={name}
   201→            placeholder="Build order name"
   202→            onChange={setName}
   203→          />
   204→        </div>
   205→        <div className="boi-field">
   206→          <span className="boi-label">Description</span>
   207→          <EscEditBox
   208→            value={description}
   209→            placeholder="Short description"
   210→            onChange={setDescription}
   211→          />
   212→        </div>
   213→        <div className="boi-field">
   214→          <span className="boi-label">Note</span>
   215→          <EscEditBox
   216→            value={note}
   217→            placeholder="Optional note"
   218→            onChange={setNote}
   219→          />
   220→        </div>
   221→      </div>
   222→
   223→      {/* ── Selectors ── */}
   224→      <div className="boi-group">
   225→        <div className="boi-field">
   226→          <span className="boi-label">Race</span>
   227→          <GlueDropdown
   228→            options={RACES}
   229→            value={race}
   230→            onChange={(v) => setRace(v as Race)}
   231→            label={(v) => RACE_LABELS[v as Race] ?? v}
   232→          />
   233→        </div>
   234→        <div className="boi-field">
   235→          <span className="boi-label">Heroes</span>
   236→          <EscEditBox
   237→            value={heroesInput}
   238→            placeholder="e.g. Death Knight, Lich"
   239→            onChange={setHeroesInput}
   240→          />
   241→        </div>
   242→        <div className="boi-field">
   243→          <span className="boi-label">vs</span>
   244→          <GlueDropdown
   245→            options={["Any" as const, ...RACES]}
   246→            value={vs || ("Any" as string)}
   247→            onChange={(v) => setVs(v === "Any" ? "" : v)}
   248→            label={(v) => (v === "Any" ? "Any" : (RACE_LABELS[v as Race] ?? v))}
   249→          />
   250→        </div>
   251→        <div className="boi-field">
   252→          <span className="boi-label">Difficulty</span>
   253→          <GlueDropdown
   254→            options={DIFFICULTIES}
   255→            value={difficulty}
   256→            onChange={(v) => setDifficulty(v as Difficulty)}
   257→          />
   258→        </div>
   259→      </div>
   260→
   261→      {/* ── Key Timing ── */}
   262→      <div className="boi-group">
   263→        <div className="boi-field">
   264→          <span className="boi-label">Key Timing (min)</span>
   265→          <EscEditBox
   266→            value={keyTimingMinute}
   267→            placeholder="e.g. 3:00"
   268→            onChange={setKeyTimingMinute}
   269→          />
   270→        </div>
   271→        <div className="boi-field">
   272→          <span className="boi-label">Timing Note</span>
   273→          <EscEditBox
   274→            value={keyTimingNote}
   275→            placeholder="Tier 2 should complete"
   276→            onChange={setKeyTimingNote}
   277→          />
   278→        </div>
   279→      </div>
   280→
   281→      {/* ── Steps ── */}
   282→      <div className="boi-table-section">
   283→        <h4 className="boi-sub-title">Steps</h4>
   284→        <div className="boi-step-list">
   285→          {steps.map((step, i) => (
   286→            <div key={i} className="boi-step-row">
   287→              <span className="boi-step-num">{i + 1}</span>
   288→              <BnetEditBox
   289→                value={step.time}
   290→                placeholder="0:00"
   291→                onChange={(v) => updateStep(i, "time", v)}
   292→              />
   293→              <BnetEditBox
   294→                value={step.instruction}
   295→                placeholder=" Instruction"
   296→                onChange={(v) => updateStep(i, "instruction", v)}
   297→              />
   298→              <BnetEditBox
   299→                value={step.food}
   300→                placeholder="5/10"
   301→                onChange={(v) => updateStep(i, "food", v)}
   302→              />
   303→              <GlueSmallButton
   304→                onClick={() => removeStep(i)}
   305→                disabled={steps.length <= 1}
   306→              >
   307→                Remove
   308→              </GlueSmallButton>
   309→            </div>
   310→          ))}
   311→        </div>
   312→        <GlueSmallButton onClick={addStep}>+ Add Step</GlueSmallButton>
   313→      </div>
   314→
   315→      {/* ── Skill Order ── */}
   316→      <div className="boi-table-section">
   317→        <h4 className="boi-sub-title">Skill Order</h4>
   318→        <div className="boi-step-list">
   319→          {skills.map((skill, i) => (
   320→            <div key={i} className="boi-skill-row">
   321→              <span className="boi-step-num">Lv{skill.level}</span>
   322→              <BnetEditBox
   323→                value={skill.skill}
   324→                placeholder="e.g. Storm Bolt"
   325→                onChange={(v) => updateSkill(i, "skill", v)}
   326→              />
   327→              <GlueSmallButton onClick={() => removeSkill(i)}>
   328→                Remove
   329→              </GlueSmallButton>
   330→            </div>
   331→          ))}
   332→        </div>
   333→        <GlueSmallButton onClick={addSkill}>+ Add Skill</GlueSmallButton>
   334→      </div>
   335→
   336→      {/* ── Submit ── */}
   337→      <div className="boi-submit">
   338→        <GlueBorderedButton onClick={handleSubmit}>
   339→          Add Build
   340→        </GlueBorderedButton>
   341→        {status && (
   342→          <span className="build-import-status boi-status">{status}</span>
   343→        )}
   344→      </div>
   345→    </section>
   346→  );
   347→}
