    91→  elapsed: number;
    92→  running: boolean;
    93→  borderImageUrl: string;
    94→}
    95→
    96→const VALID_RACES = new Set<string>(["Human", "Orc", "NightElf", "Undead"]);
    97→
    98→function BuildCard({
    99→  build,
   100→  elapsed,
   101→  running,
   102→  borderImageUrl,
   103→}: BuildCardProps) {
