  color: var(--wc3-gold);
  text-transform: uppercase;
  letter-spacing: 0.12em;
  font-weight: normal;
  display: flex;
  align-items: center;
  gap: 0.75rem;
  text-shadow: 0 0 6px rgba(252, 211, 18, 0.25);
}

.skill-order-title::before,
