import { useCallback, useEffect, useRef, useState } from "react";
import {
  useTimerRunning,
  useElapsedSeconds,
  startTimer,
  pauseTimer,
  resetTimer,
} from "../../state/timer";
import { useCurrentRace, setCurrentRace } from "../../state/race";
import type { Race } from "../../lib/types";
import GlueSmallButton from "../GlueSmallButton";
import GlueBorderedButton from "../GlueBorderedButton";
import GlueDropdown from "../GlueDropdown";
import GlueScrollbar from "../GlueScrollbar";
import { useBuildOrders, importBuilds } from "../../state/buildOrders";
import type { BuildOrder } from "../../data/buildOrders";

const RACES: Race[] = ["Human", "Orc", "NightElf", "Undead"];
const RACE_LABELS: Record<Race, string> = {
  Human: "Human",
  Orc: "Orc",
  NightElf: "Night Elf",
  Undead: "Undead",
};
import {
  loadBlpDataUrl,
  loadDataUrlImage,
  composeBorderImageFromAtlas,
} from "../../utils/glueButton";
import SkillOrderSection from "../SkillOrderSection";
import BuildOrderInputSection from "./BuildOrderInputSection";
import FooterSection from "./FooterSection";

function formatTime(seconds: number): string {
  const m = Math.floor(seconds / 60);
  const s = seconds % 60;
  return `${m}:${s.toString().padStart(2, "0")}`;
}

function parseStepTime(time: string): number {
  const [m, s] = time.split(":").map(Number);
  return m * 60 + (s ?? 0);
}

function getCardBorderPath(race: Race | null): string {
  if (race === "Orc") return "./buttons/esc/orc/orc-options-menu-border.blp";
  if (race === "NightElf")
    return "./buttons/esc/nightelf/nightelf-options-menu-border.blp";
  if (race === "Undead")
    return "./buttons/esc/undead/undead-options-menu-border.blp";
  return "./buttons/esc/human/human-options-menu-border.blp";
}

function useCardBorderImage(race: Race | null): string {
  const [borderImageUrl, setBorderImageUrl] = useState("");

  useEffect(() => {
    let cancelled = false;
    const path = getCardBorderPath(race);
    void loadBlpDataUrl(path)
      .then((url) => loadDataUrlImage(url))
      .then((img) => {
        if (cancelled) return;
        setBorderImageUrl(composeBorderImageFromAtlas(img));
      })
      .catch((err) => console.error(err));
    return () => {
      cancelled = true;
    };
  }, [race]);

  return borderImageUrl;
}

function useSupplyIcon(): string {
  const [url, setUrl] = useState("");
  useEffect(() => {
    void loadBlpDataUrl("./resources/ResourceSupply.blp").then(setUrl);
  }, []);
  return url;
}

const DIFFICULTY_CLASS: Record<string, string> = {
  Beginner: "build-card-difficulty--beginner",
  Intermediate: "build-card-difficulty--intermediate",
  Advanced: "build-card-difficulty--advanced",
};

const HERO_ICONS: Record<string, string> = {
  Archmage: "BTNHeroArchMage",
  Blademaster: "BTNHeroBlademaster",
  "Blood Mage": "BTNHeroBloodElfPrince",
  "Crypt Lord": "BTNHeroCryptLord",
  "Death Knight": "BTNHeroDeathKnight",
  "Demon Hunter": "BTNHeroDemonHunter",
  "Far Seer": "BTNHeroFarseer",
  "Keeper of the Grove": "BTNKeeperOfTheGrove",
  Lich: "BTNHeroLich",
  "Mountain King": "BTNHeroMountainKing",
  Paladin: "BTNHeroPaladin",
  "Priestess of the Moon": "BTNPriestessOfTheMoon",
  "Shadow Hunter": "BTNShadowHunter",
  "Tauren Chieftain": "BTNHeroTaurenChieftain",
  Warden: "BTNHeroWarden",
};

function HeroIcon({ heroName }: { heroName: string }) {
  const [iconUrl, setIconUrl] = useState("");

  useEffect(() => {
    let cancelled = false;
    const file = HERO_ICONS[heroName];
    if (!file) return;
    void loadBlpDataUrl(`./buttons/command/${file}.blp`).then((url) => {
      if (!cancelled) setIconUrl(url);
    });
    return () => {
      cancelled = true;
    };
  }, [heroName]);

  if (!iconUrl) return null;
  return (
    <img
      src={iconUrl}
      alt={heroName}
      title={heroName}
      className="build-card-hero-icon"
    />
  );
}

interface BuildCardProps {
  build: BuildOrder;
  elapsed: number;
  running: boolean;
  borderImageUrl: string;
}

const VALID_RACES = new Set<string>(["Human", "Orc", "NightElf", "Undead"]);

function BuildCard({
  build,
  elapsed,
  running,
  borderImageUrl,
}: BuildCardProps) {
  const tableRef = useRef<HTMLDivElement>(null);
  const [scrollPct, setScrollPct] = useState(0);
  const scrollingFromBar = useRef(false);
  const supplyIconUrl = useSupplyIcon();
  const buildRace = VALID_RACES.has(build.race) ? (build.race as Race) : null;

  const activeStepIndex = (() => {
    let idx = -1;
    for (let i = 0; i < build.steps.length; i++) {
      if (parseStepTime(build.steps[i].time) <= elapsed) idx = i;
    }
    return idx;
  })();

  // Sync native scroll → scrollbar percentage
  useEffect(() => {
    const el = tableRef.current;
    if (!el) return;
    const handler = () => {
      if (scrollingFromBar.current) return;
      const maxScroll = el.scrollHeight - el.clientHeight;
      if (maxScroll <= 0) {
        setScrollPct(0);
        return;
      }
      setScrollPct((el.scrollTop / maxScroll) * 100);
    };
    el.addEventListener("scroll", handler, { passive: true });
    return () => el.removeEventListener("scroll", handler);
  }, []);

  // Scrollbar → native scroll
  const handleScrollbarChange = useCallback((pct: number) => {
    setScrollPct(pct);
    const el = tableRef.current;
    if (!el) return;
    const maxScroll = el.scrollHeight - el.clientHeight;
    if (maxScroll <= 0) return;
    scrollingFromBar.current = true;
    el.scrollTop = (pct / 100) * maxScroll;
    requestAnimationFrame(() => {
      scrollingFromBar.current = false;
    });
  }, []);

  // Auto-scroll the active step into view
  useEffect(() => {
    if (activeStepIndex < 0 || !tableRef.current) return;
    const row = tableRef.current.querySelectorAll(".build-step-row")[
      activeStepIndex
    ] as HTMLElement | undefined;
    if (row) {
      row.scrollIntoView({ block: "nearest", behavior: "smooth" });
    }
  }, [activeStepIndex]);

  // border-image applied only to the active row; all rows already reserve
  // 6px transparent border space in CSS so nothing shifts.
  const activeBorderStyle: React.CSSProperties | undefined = borderImageUrl
    ? {
        borderImageSource: `url("${borderImageUrl}")`,
        borderImageSlice: 64,
        borderImageWidth: 1,
        borderImageRepeat: "round",
      }
    : undefined;

  return (
    <div className="build-card">
      {/* Left column */}
      <div className="build-card-info">
        <div className="build-card-header">
          {build.heroes.length > 0 && <HeroIcon heroName={build.heroes[0]} />}
          <div className="build-card-header-text">
            <h4 className="build-card-title">{build.name}</h4>
            <div className="build-card-subtitle">
              {build.vs && (
                <span className="build-card-matchup">Good vs {build.vs}</span>
              )}
              {build.difficulty && (
                <span
                  className={`build-card-difficulty ${DIFFICULTY_CLASS[build.difficulty] ?? ""}`}
                >
                  {build.difficulty}
                </span>
              )}
            </div>
          </div>
        </div>

        <div className="build-card-body">
          {build.description && (
            <p className="build-card-desc">{build.description}</p>
          )}
          {build.note && <p className="build-card-note">{build.note}</p>}
          {build.keyTiming && (
            <div className="build-card-key-timing">
              <span className="build-card-key-timing-label">Key timing</span>{" "}
              {formatTime(build.keyTiming.minute * 60)} – {build.keyTiming.note}
            </div>
          )}
        </div>

        <div className="build-card-timer">
          <span className="build-card-elapsed">{formatTime(elapsed)}</span>
          <div className="build-card-controls">
            <GlueSmallButton onClick={running ? pauseTimer : startTimer}>
              {running ? "Pause" : "Start"}
            </GlueSmallButton>
            <GlueSmallButton
              onClick={resetTimer}
              disabled={elapsed === 0 && !running}
            >
              Reset
            </GlueSmallButton>
          </div>
        </div>
      </div>

      {/* Right column */}
      <div className="build-card-steps-wrapper">
        <div className="build-card-steps" ref={tableRef}>
          <table className="build-steps-table">
            <thead>
              <tr>
                <th>#</th>
                <th>Time</th>
                <th>Instruction</th>
                <th>
                  {supplyIconUrl && (
                    <img
                      src={supplyIconUrl}
                      alt=""
                      className="build-step-food-icon"
                    />
                  )}
                  Food
                </th>
              </tr>
            </thead>
            <tbody>
              {build.steps.map((step, j) => {
                const isActive = j === activeStepIndex;
                const isPast = j < activeStepIndex;
                return (
                  <tr
                    key={j}
                    className={`build-step-row${isPast ? " build-step-row--past" : ""}${isActive ? " build-step-row--active" : ""}`}
                    style={isActive ? activeBorderStyle : undefined}
                  >
                    <td className="build-step-order">{step.order}</td>
                    <td className="build-step-time">{step.time}</td>
                    <td className="build-step-instruction">
                      {step.instruction}
                    </td>
                    <td className="build-step-food">
                      {supplyIconUrl && (
                        <img
                          src={supplyIconUrl}
                          alt=""
                          className="build-step-food-icon"
                        />
                      )}
                      {step.food}
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
        <GlueScrollbar value={scrollPct} onChange={handleScrollbarChange} />
      </div>
    </div>
  );
}

export default function BuildOrdersSection() {
  const running = useTimerRunning();
  const elapsed = useElapsedSeconds();
  const currentRace = useCurrentRace();
  const borderImageUrl = useCardBorderImage(currentRace);
  const allBuilds = useBuildOrders();

  const relevantBuilds = allBuilds.filter(
    (b) => !currentRace || b.race === currentRace,
  );

  const [selectedIndex, setSelectedIndex] = useState(0);
  const [importStatus, setImportStatus] = useState("");
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Reset selection and timer when race changes
  useEffect(() => {
    setSelectedIndex(0);
    resetTimer();
  }, [currentRace]);

  const selectedBuild =
    relevantBuilds.length > 0
      ? relevantBuilds[Math.min(selectedIndex, relevantBuilds.length - 1)]
      : null;

  // Build dropdown option keys — use indices as stable identifiers
  const optionKeys = relevantBuilds.map((_, i) => String(i));

  const handleImport = useCallback(() => {
    fileInputRef.current?.click();
  }, []);

  const handleExport = useCallback(() => {
    if (!selectedBuild) return;
    // Build a clean object with properties ordered to match the BuildOrder interface
    const clean: Record<string, unknown> = {
      name: selectedBuild.name,
      race: selectedBuild.race,
    };
    if (selectedBuild.vs) clean.vs = selectedBuild.vs;
    clean.description = selectedBuild.description;
    if (selectedBuild.difficulty) clean.difficulty = selectedBuild.difficulty;
    if (selectedBuild.keyTiming) clean.keyTiming = selectedBuild.keyTiming;
    clean.steps = selectedBuild.steps;
    if (selectedBuild.note) clean.note = selectedBuild.note;
    if (selectedBuild.skillOrder && selectedBuild.skillOrder.length > 0) {
      clean.skillOrder = selectedBuild.skillOrder;
    }
    const json = JSON.stringify([clean], null, 2);
    const blob = new Blob([json], { type: "application/json" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `${selectedBuild.name.replace(/[^a-zA-Z0-9_-]/g, "_")}.json`;
    a.click();

    URL.revokeObjectURL(url);
  }, [selectedBuild]);

  const handleFileChange = useCallback(
    (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file) return;

      const reader = new FileReader();
      reader.onload = () => {
        try {
          const json = JSON.parse(reader.result as string);
          const count = importBuilds(json);
          if (count > 0) {
            setImportStatus(`Imported ${count} build${count > 1 ? "s" : ""}`);
          } else {
            setImportStatus("No valid builds found in file");
          }
        } catch {
          setImportStatus("Invalid JSON file");
        }
        // Clear so the same file can be re-imported
        e.target.value = "";
        setTimeout(() => setImportStatus(""), 4000);
      };
      reader.readAsText(file);
    },
    [],
  );

  return (
    <div className="tab-content">
      <section className="section-card build-orders-section">
        <div className="build-orders-toolbar">
          <h3>Build Orders</h3>
          <div className="build-orders-toolbar-actions">
            <div className="build-orders-race-picker">
              <GlueDropdown
                options={RACES}
                value={currentRace}
                onChange={(v) => setCurrentRace(v as Race)}
                label={(v) => RACE_LABELS[v as Race] ?? v}
              />
            </div>
            {relevantBuilds.length > 1 && (
              <GlueDropdown
                options={optionKeys}
                value={String(
                  Math.min(selectedIndex, relevantBuilds.length - 1),
                )}
                onChange={(v) => {
                  setSelectedIndex(Number(v));
                  resetTimer();
                }}
                label={(v) => relevantBuilds[Number(v)]?.name ?? ""}
              />
            )}
            <GlueBorderedButton onClick={handleImport}>
              Import
            </GlueBorderedButton>
            <GlueBorderedButton
              onClick={handleExport}
              disabled={!selectedBuild}
            >
              Export
            </GlueBorderedButton>
            <input
              ref={fileInputRef}
              type="file"
              accept=".json"
              className="build-import-input"
              onChange={handleFileChange}
            />
          </div>
        </div>
        {importStatus && (
          <div className="build-import-status">{importStatus}</div>
        )}

        {!selectedBuild ? (
          <p className="build-card-empty">
            No build orders available for this race.
          </p>
        ) : (
          <>
            <BuildCard
              key={`${currentRace}-${selectedIndex}`}
              build={selectedBuild}
              elapsed={elapsed}
              running={running}
              borderImageUrl={borderImageUrl}
            />
            {selectedBuild.skillOrder &&
              selectedBuild.skillOrder.length > 0 && (
                <SkillOrderSection skillOrder={selectedBuild.skillOrder} />
              )}
            <BuildOrderInputSection />
          </>
        )}
      </section>
      <FooterSection race={currentRace} />
    </div>
  );
}

import { createExternalStore } from "./createStore";
import { BUILD_ORDERS_2026 } from "../data/buildOrders";
import type { BuildOrder, SkillPick } from "../data/buildOrders";

const VALID_RACES = new Set(["Human", "Orc", "NightElf", "Undead"]);

const store = createExternalStore<BuildOrder[]>([...BUILD_ORDERS_2026]);

export const useBuildOrders = store.useValue;
export const getBuildOrders = store.get;

/** Validate and add builds, returning the count of successfully imported entries. */
export function importBuilds(data: unknown): number {
  if (!Array.isArray(data)) {
    // Allow a single object wrapped as an array
    if (data && typeof data === "object" && "steps" in data) {
      data = [data];
    } else {
      return 0;
    }
  }

  const valid: BuildOrder[] = [];
  for (const item of data as unknown[]) {
    if (!item || typeof item !== "object") continue;
    const obj = item as Record<string, unknown>;

    if (typeof obj.name !== "string" || !obj.name) continue;
    if (typeof obj.race !== "string" || !VALID_RACES.has(obj.race)) continue;
    if (!Array.isArray(obj.steps) || obj.steps.length === 0) continue;

    const steps: { order: number; time: string; instruction: string; food: string }[] = [];
    let stepsOk = true;
    for (const s of obj.steps) {
      if (!s || typeof s !== "object") { stepsOk = false; break; }
      const st = s as Record<string, unknown>;
      if (typeof st.order !== "number") { stepsOk = false; break; }
      if (typeof st.time !== "string") { stepsOk = false; break; }
      if (typeof st.instruction !== "string") { stepsOk = false; break; }
      if (typeof st.food !== "string") { stepsOk = false; break; }
      steps.push({
        order: st.order,
        time: st.time,
        instruction: st.instruction,
        food: st.food,
      });
    }
    if (!stepsOk) continue;

    valid.push({
      name: obj.name,
      race: obj.race,
      heroes: Array.isArray(obj.heroes)
        ? (obj.heroes as unknown[]).filter((h): h is string => typeof h === "string")
        : [],
      description: typeof obj.description === "string" ? obj.description : "",
      vs: typeof obj.vs === "string" ? obj.vs : undefined,
      difficulty:
        obj.difficulty === "Beginner" ||
        obj.difficulty === "Intermediate" ||
        obj.difficulty === "Advanced"
          ? obj.difficulty
          : undefined,
      keyTiming:
        obj.keyTiming &&
        typeof obj.keyTiming === "object" &&
        typeof (obj.keyTiming as Record<string, unknown>).minute === "number" &&
        typeof (obj.keyTiming as Record<string, unknown>).note === "string"
          ? (obj.keyTiming as { minute: number; note: string })
          : undefined,
      note: typeof obj.note === "string" ? obj.note : undefined,
      steps,
      skillOrder: Array.isArray(obj.skillOrder)
        ? (obj.skillOrder as unknown[])
            .filter(
              (s): s is SkillPick =>
                !!s &&
                typeof s === "object" &&
                typeof (s as Record<string, unknown>).level === "number" &&
                typeof (s as Record<string, unknown>).skill === "string",
            )
            .map((s) => ({
              level: s.level,
              skill: s.skill,
              icon: typeof s.icon === "string" ? s.icon : undefined,
            }))
        : undefined,
    });
  }

  if (valid.length === 0) return 0;

  store.set((prev) => [...prev, ...valid]);
  return valid.length;
}

