  pointer-events: none;
}

.esc-textarea-mask {
  position: absolute;
  inset: 11px 15px;
  overflow: hidden;
  z-index: 2;
}

.esc-textarea-content {
  position: absolute;
  inset: 0;
  padding: 2px 10px 2px 8px;
  z-index: 2;
  color: #d8def5;
  font-size: 0.78rem;
  text-align: left;
  white-space: pre;
  text-shadow: 1px 1px 0 rgba(0, 0, 0, 0.92);
