  margin: 0;
  cursor: pointer;
}

.cmd-overlay-button {
  position: relative;
  width: 48px;
  height: 48px;
  border: 2px solid #1a1a2e;
  border-radius: 2px;
  overflow: hidden;
  background: #000;
}

.cmd-overlay-button--showcase {
  width: 64px;
  height: 64px;
}

.cmd-overlay-base,
.cmd-overlay-layer,
.cmd-overlay-level {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  display: block;
  image-rendering: pixelated;
  pointer-events: none;
}

.cmd-overlay-add {
  mix-blend-mode: screen;
}

/* Loading Screen */
.loading-screen {
  position: fixed;
  inset: 0;
  z-index: 1000;
  display: flex;
  align-items: center;
  justify-content: center;
  background: #05080f;
  transition: opacity 400ms ease;
}

.loading-screen--fading {
  opacity: 0;
  pointer-events: none;
}

.loading-screen-bg {
  position: absolute;
  inset: 0;
  /* Placeholder gradient — swap for a WC3 loading screen image later:
     background: url("/loading/loading-screen-bg.jpg") center / cover no-repeat; */
  background: radial-gradient(
    ellipse at 50% 40%,
    #1a2440 0%,
    #0a0e1a 70%,
    #05080f 100%
  );
}

.loading-screen-content {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 24px;
  width: min(560px, 90vw);
}

.loading-screen-logo {
  width: min(340px, 70vw);
  height: auto;
  filter: drop-shadow(0 2px 12px rgba(0, 0, 0, 0.8));
  user-select: none;
  -webkit-user-drag: none;
}

.loading-screen-bar-wrap {
  width: 100%;
}

.loading-screen-label {
  margin: 0;
  color: #7c8fb5;
  font-size: 0.82rem;
  letter-spacing: 0.08em;
  text-transform: uppercase;
}

/* Hero Section */
.hero-section {
  text-align: center;
  padding: 24px 24px 32px;
  margin-bottom: 24px;
}

.hero-content {
  position: relative;
}

.hero-logo {
  display: block;
  margin: 0 auto 8px;
  width: min(420px, 60vw);
  height: auto;
  filter: drop-shadow(0 2px 6px rgba(0, 0, 0, 0.6));
