}

.hero-subtitle {
  margin: 0 0 12px;
  color: #d3ddfb;
  font-size: 1.3rem;
}

.hero-description {
  margin: 0 0 24px;
  color: #9aa4c0;
  font-size: 0.95rem;
  line-height: 1.5;
  max-width: 600px;
  margin-left: auto;
  margin-right: auto;
}

.hero-description strong {
  color: #eceff7;
}

.hero-cta-row {
  display: flex;
  gap: 12px;
  justify-content: center;
  margin-bottom: 16px;
}

.hero-cta-row--components {
  align-items: center;
  flex-wrap: wrap;
  gap: 6px;
}

.home-cta-row {
  display: flex;
  gap: 16px;
  justify-content: center;
  margin-bottom: 16px;
}

.home-cta-row .esc-option-preview {
  width: 170px;
  height: 44px;
}

.hero-get-started-btn {
  width: 150px;
  height: 40px;
  flex: 0 0 150px;
  margin: 0;
}

.hero-install-editbox {
  width: 150px;
  height: 40px;
  flex: 0 0 150px;
  margin: 0;
  cursor: pointer;
}

.hero-install-editbox input {
  text-align: center;
  color: var(--wc3-gold);
  font-family:
    "Friz Quadrata", "Palatino Linotype", "Book Antiqua", Palatino, serif;
  font-size: 0.9rem;
  line-height: 1;
  cursor: pointer;
  padding: 0 8px;
}

.hero-footer {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 8px;
  margin-top: 4px;
}

.hero-footer-divider {
  width: 120px;
