.faction-preview-samples {
  display: flex;
  flex-direction: column;
  gap: 6px;
  align-items: center;
}

.faction-preview-control {
  width: min(100%, 192px);
  max-width: 192px;
}

.faction-preview-control-label {
  margin: 0 0 4px;
  color: #7982a0;
  font-size: 0.64rem;
  letter-spacing: 0.06em;
  text-transform: uppercase;
}

.faction-preview-option-button {
