html,
body,
#root {
  margin: 0;
  width: 100%;
  height: 100%;
}

body {
  background: #08080f;
  color: #fff;
  overflow: hidden;
  font-family:
    "Friz Quadrata", "Palatino Linotype", "Book Antiqua", Palatino, serif;
}

:root {
  --card-bg: #111118;
  --card-border: #222233;
  --wc3-white: #ffffff;
  --wc3-gold: #fcd312;
  --wc3-dark-gold: #cca300;
