file.content:
  width: 100px;
  height: 40px;
  font-size: 0.84rem;
  flex-shrink: 0;
}

.build-import-input {
  display: none;
}

.build-import-status {
  font-size: 0.78rem;
  color: var(--wc3-gold);
  padding: 0.3rem 0.6rem;
  margin-bottom: 0.75rem;
  background: rgba(252, 211, 18, 0.08);
  border: 1px solid rgba(252, 211, 18, 0.2);
}

.build-card-empty {
  text-align: center;
  color: rgba(252, 211, 18, 0.6);
  padding: 2rem 0;
}

/* ── Per-build card ── */
.build-card {
  display: grid;
  grid-template-columns: 310px 1fr;
  gap: 0;
  background: rgba(0, 0, 0, 0.55);
  border: 1px solid rgba(252, 211, 18, 0.25);
}

/* ── Left column ── */
.build-card-info {
  padding: 1.25rem 1.5rem;
  border-right: 1px solid rgba(252, 211, 18, 0.2);
  display: flex;
  flex-direction: column;
  gap: 0.85rem;
}

/* Identity row: hero icon column + title block */
.build-card-identity {
  display: flex;
  flex-direction: row;
  align-items: flex-start;
  gap: 1rem;
  padding-bottom: 0.85rem;
  border-bottom: 1px solid rgba(252, 211, 18, 0.12);
  background: linear-gradient(180deg, rgba(252, 211, 18, 0.04) 0%, transparent 100%);
  margin: -1.25rem -1.5rem 0;
  padding: 1rem 1.5rem 0.85rem;
}

/* Hero icon + name stacked */
.build-card-hero-col {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 0.3rem;
  flex-shrink: 0;
}

.build-card-hero-icon {
  width: 64px;
  height: 64px;
  image-rendering: pixelated;
  border: 2px solid rgba(252, 211, 18, 0.55);
  box-shadow:
    0 0 6px rgba(252, 211, 18, 0.25),
    inset 0 0 8px rgba(0, 0, 0, 0.6);
  display: block;
}

.build-card-hero-name {
  font-size: 0.62rem;
  color: #b8a060;
  text-align: center;
  text-transform: uppercase;
  letter-spacing: 0.04em;
  max-width: 64px;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

/* Title + badges */
.build-card-identity-text {
  display: flex;
  flex-direction: column;
  gap: 0.4rem;
  min-width: 0;
  padding-top: 2px;
}

.build-card-title {
  margin: 0;
  font-size: 1.05rem;
  font-weight: bold;
  color: var(--wc3-gold);
  text-shadow: 1px 1px 0 rgba(0, 0, 0, 0.9);
  line-height: 1.3;
}

.build-card-badges {
  display: flex;
  gap: 0.5rem;
  align-items: center;
  flex-wrap: wrap;
  font-size: 0.72rem;
}

.build-card-portrait {
  position: relative;
  width: 50px;
  height: 80px;
  flex-shrink: 0;
}

.build-card-portrait-window {
  position: absolute;
  inset: 0;
  -webkit-mask-image: var(--portrait-window-mask);
  mask-image: var(--portrait-window-mask);
  -webkit-mask-repeat: no-repeat;
  mask-repeat: no-repeat;
  -webkit-mask-size: 100% 100%;
  mask-size: 100% 100%;
  -webkit-mask-position: center;
  mask-position: center;
  overflow: hidden;
  background: #000;
  z-index: 1;
}

.build-card-portrait-frame {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  object-fit: fill;
  pointer-events: none;
  z-index: 2;
}

.build-card-matchup {
  margin: 0;
  color: #c8b97a;
  font-style: italic;
}

.build-card-difficulty {
  margin: 0;
  padding: 1px 6px;
  border-radius: 2px;
  font-style: normal;
  font-size: 0.65rem;
  text-transform: uppercase;
  letter-spacing: 0.05em;
}

.build-card-difficulty--beginner {
  background: rgba(76, 175, 80, 0.2);
  color: #81c784;
  border: 1px solid rgba(76, 175, 80, 0.35);
}

.build-card-difficulty--intermediate {
  background: rgba(252, 211, 18, 0.12);
  color: var(--wc3-gold);
  border: 1px solid rgba(252, 211, 18, 0.3);
}

.build-card-difficulty--advanced {
  background: rgba(244, 67, 54, 0.15);
  color: #ef9a9a;
  border: 1px solid rgba(244, 67, 54, 0.35);
}

.build-card-body {
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
  flex: 1;
}

.build-card-desc {
  margin: 0;
  font-size: 0.78rem;
  color: #dbe4ff;
  line-height: 1.55;
}

.build-card-note {
  margin: 0;
  font-size: 0.72rem;
  color: rgba(252, 211, 18, 0.65);
  font-style: italic;
  line-height: 1.5;
  padding-left: 0.5rem;
  border-left: 2px solid rgba(252, 211, 18, 0.2);
}

.build-card-key-timing {
  font-size: 0.75rem;
  color: #c8b97a;
  padding: 0.3rem 0.5rem;
  border: 1px solid rgba(252, 211, 18, 0.2);
  background: rgba(252, 211, 18, 0.05);
  line-height: 1.4;
}

.build-card-key-timing-label {
  color: var(--wc3-gold);
  font-weight: bold;
}

.build-card-timer {
  margin-top: auto;
  padding-top: 0.75rem;
  border-top: 1px solid rgba(252, 211, 18, 0.12);
  display: flex;
  align-items: center;
  gap: 0.75rem;
}

.build-card-elapsed {
  font-size: 1.4rem;
  color: var(--wc3-gold);
  text-shadow: 0 0 8px rgba(252, 211, 18, 0.5);
  font-variant-numeric: tabular-nums;
  letter-spacing: 0.05em;
  min-width: 4ch;
}

.build-card-controls {
  display: flex;
  gap: 0.25rem;
  flex-wrap: wrap;
}

/* ── Right column: step table ── */
.build-card-steps-wrapper {
  display: flex;
  flex-direction: row;
  min-height: 0;
}

