/* Loading Screen */
.loading-screen {
  position: fixed;
  inset: 0;
  z-index: 1000;
  display: flex;
  align-items: center;
  justify-content: center;
  background: #05080f;
  transition: opacity 400ms ease;
}

.loading-screen--fading {
  opacity: 0;
  pointer-events: none;
}

.loading-screen-bg {
  position: absolute;
  inset: 0;
  /* Placeholder gradient — swap for a WC3 loading screen image later:
     background: url("/loading/loading-screen-bg.jpg") center / cover no-repeat; */
  background: radial-gradient(
    ellipse at 50% 40%,
    #1a2440 0%,
    #0a0e1a 70%,
    #05080f 100%
  );
}

.loading-screen-content {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 24px;
  width: min(560px, 90vw);
}

.loading-screen-logo {
  width: min(340px, 70vw);
  height: auto;
  filter: drop-shadow(0 2px 12px rgba(0, 0, 0, 0.8));
  user-select: none;
  -webkit-user-drag: none;
}

.loading-screen-bar-wrap {
  width: 100%;
}

.loading-screen-label {
  margin: 0;
  color: #7c8fb5;
  font-size: 0.82rem;
  letter-spacing: 0.08em;
  text-transform: uppercase;
}

/* Hero Section */
.hero-section {
