/* Loading Screen */
.loading-screen {
  position: fixed;
  inset: 0;
  z-index: 1000;
  display: flex;
  align-items: center;
  justify-content: center;
  background: #05080f;
  transition: opacity 400ms ease;
}

.loading-screen--fading {
  opacity: 0;
  pointer-events: none;
}

.loading-screen-bg {
  position: absolute;
  inset: 0;
  /* Placeholder gradient — swap for a WC3 loading screen image later:
     background: url("/loading/loading-screen-bg.jpg") center / cover no-repeat; */
  background: radial-gradient(
    ellipse at 50% 40%,
    #1a2440 0%,
    #0a0e1a 70%,
    #05080f 100%
  );
}

