  padding: 1.5rem;
}

/* ── Build order toolbar ── */
.build-orders-toolbar {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 1rem;
  margin-bottom: 1rem;
  flex-wrap: wrap;
}

.build-orders-toolbar h3 {
  margin: 0;
  white-space: nowrap;
}

.build-orders-toolbar-actions {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  flex: 1;
  justify-content: flex-end;
  min-width: 0;
}

/* Race picker — compact fixed width */
.build-orders-race-picker {
  flex-shrink: 0;
  width: 120px;
}

.build-orders-race-picker .popup-trigger-anchor {
  width: 100%;
}

.build-orders-race-picker .popup-trigger-button {
  width: 100%;
  height: 40px;
}

.build-orders-race-picker .popup-menu-demo {
  width: 100%;
}

/* Build selector — flexible */
.build-orders-toolbar-actions > .popup-trigger-anchor {
  width: auto;
  min-width: 180px;
  max-width: 420px;
  flex: 1;
}

.build-orders-toolbar-actions > .popup-trigger-anchor > .popup-trigger-button {
  width: 100%;
  height: 40px;
}

.build-orders-toolbar-actions > .popup-trigger-anchor > .popup-menu-demo {
  width: 100%;
}

.build-orders-toolbar-actions .glue-screen-button {
  width: 100px;
  height: 40px;
  font-size: 0.84rem;
  flex-shrink: 0;
}

.build-import-input {
  display: none;
}

.build-import-status {
  font-size: 0.78rem;
  color: var(--wc3-gold);
  padding: 0.3rem 0.6rem;
  margin-bottom: 0.75rem;
  background: rgba(252, 211, 18, 0.08);
  border: 1px solid rgba(252, 211, 18, 0.2);
}

.build-card-empty {
  text-align: center;
  color: rgba(252, 211, 18, 0.6);
  padding: 2rem 0;
}

/* ── Per-build card ── */
.build-card {
  display: grid;
  grid-template-columns: 280px 1fr;
  grid-template-rows: auto 1fr;
  grid-template-areas:
    "header header"
    "info   steps";
  background: rgba(0, 0, 0, 0.55);
  border: 1px solid rgba(252, 211, 18, 0.25);
}

/* ── Header banner (full width, fixed height) ── */
.build-card-header {
  grid-area: header;
  display: flex;
  flex-direction: row;
  align-items: stretch; /* all children same height */
  gap: 1.1rem;
  padding: 0.75rem 1.5rem;
  background: linear-gradient(
    180deg,
    rgba(252, 211, 18, 0.07) 0%,
    rgba(0, 0, 0, 0) 100%
  );
  border-bottom: 1px solid rgba(252, 211, 18, 0.18);
}

/* Hero icon column — exactly 64px, name as overlay */
.build-card-hero-col {
  position: relative;
  width: 64px;
  height: 64px;
  flex-shrink: 0;
  align-self: center;
}

.build-card-hero-icon {
  width: 64px;
  height: 64px;
  image-rendering: pixelated;
  border: 2px solid rgba(252, 211, 18, 0.55);
  box-shadow:
    0 0 8px rgba(252, 211, 18, 0.2),
    inset 0 0 10px rgba(0, 0, 0, 0.6);
  display: block;
}

/* Hero name: overlay at bottom of icon — adds zero height */
.build-card-hero-name {
  position: absolute;
  bottom: 0;
  left: 0;
  right: 0;
  background: rgba(0, 0, 0, 0.72);
  font-size: 0.52rem;
  color: #c8a855;
  text-align: center;
  text-transform: uppercase;
  letter-spacing: 0.06em;
  padding: 2px 2px;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  line-height: 1.4;
}

/* Title + badges — same 64px height as icon */
.build-card-header-main {
  flex: 1;
  min-width: 0;
  height: 64px;
  align-self: center;
  display: flex;
  flex-direction: column;
  justify-content: space-between;
  overflow: hidden;
}

.build-card-title {
  margin: 0;
  font-size: 1.05rem;
  font-weight: bold;
  color: var(--wc3-gold);
  text-shadow: 1px 1px 0 rgba(0, 0, 0, 0.9);
  line-height: 1.25;
  /* clamp to 2 lines */
  display: -webkit-box;
  -webkit-line-clamp: 2;
  -webkit-box-orient: vertical;
  overflow: hidden;
}

.build-card-badges {
  display: flex;
  gap: 0.5rem;
  align-items: center;
  flex-wrap: nowrap;
  flex-shrink: 0;
}

/* ── Header skill bar (right side, same 64px height) ── */
.build-card-header-skills {
  margin-left: auto;
  flex-shrink: 0;
  height: 64px;
  align-self: center;
  display: flex;
  flex-direction: column;
  justify-content: space-between;
  align-items: flex-start;
  padding-left: 1.1rem;
  border-left: 1px solid rgba(252, 211, 18, 0.15);
}

.build-card-header-skills-label {
  font-size: 0.55rem;
  color: rgba(252, 211, 18, 0.4);
  text-transform: uppercase;
  letter-spacing: 0.1em;
  line-height: 1;
}

.build-card-header-skills-row {
  display: flex;
  flex-direction: row;
  gap: 3px;
  flex-wrap: nowrap;
  align-items: flex-end;
}

.header-skill-icon-wrap {
  position: relative;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 2px;
  cursor: default;
}

.header-skill-level {
  font-size: 0.52rem;
  color: #a89050;
  letter-spacing: 0.02em;
  line-height: 1;
}

.header-skill-icon {
  width: 36px;
  height: 36px;
  image-rendering: pixelated;
  border: 1px solid rgba(252, 211, 18, 0.3);
  display: block;
}

.header-skill-icon--placeholder {
  background: rgba(252, 211, 18, 0.05);
}

/* ── Left info column ── */
.build-card-info {
  grid-area: info;
  padding: 1rem 1.25rem;
  border-right: 1px solid rgba(252, 211, 18, 0.15);
  display: flex;
  flex-direction: column;
  gap: 0.75rem;
}

.build-card-portrait {
  position: relative;
  width: 50px;
  height: 80px;
  flex-shrink: 0;
}

.build-card-portrait-window {
  position: absolute;
  inset: 0;
  -webkit-mask-image: var(--portrait-window-mask);
  mask-image: var(--portrait-window-mask);
  -webkit-mask-repeat: no-repeat;
  mask-repeat: no-repeat;
  -webkit-mask-size: 100% 100%;
  mask-size: 100% 100%;
  -webkit-mask-position: center;
  mask-position: center;
  overflow: hidden;
  background: #000;
  z-index: 1;
}

.build-card-portrait-frame {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  object-fit: fill;
  pointer-events: none;
  z-index: 2;
}

.build-card-matchup {
  margin: 0;
  color: #c8b97a;
  font-style: italic;
}

.build-card-difficulty {
  margin: 0;
  padding: 1px 6px;
  border-radius: 2px;
  font-style: normal;
  font-size: 0.65rem;
  text-transform: uppercase;
  letter-spacing: 0.05em;
}

.build-card-difficulty--beginner {
  background: rgba(76, 175, 80, 0.2);
  color: #81c784;
  border: 1px solid rgba(76, 175, 80, 0.35);
}

.build-card-difficulty--intermediate {
  background: rgba(252, 211, 18, 0.12);
  color: var(--wc3-gold);
  border: 1px solid rgba(252, 211, 18, 0.3);
}

.build-card-difficulty--advanced {
  background: rgba(244, 67, 54, 0.15);
  color: #ef9a9a;
  border: 1px solid rgba(244, 67, 54, 0.35);
}

.build-card-body {
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
  flex: 1;
}

.build-card-desc {
  margin: 0;
  font-size: 0.78rem;
  color: #dbe4ff;
  line-height: 1.55;
}

.build-card-note {
  margin: 0;
  font-size: 0.72rem;
  color: rgba(252, 211, 18, 0.65);
  font-style: italic;
  line-height: 1.5;
  padding-left: 0.5rem;
  border-left: 2px solid rgba(252, 211, 18, 0.2);
}

.build-card-key-timing {
  font-size: 0.75rem;
  color: #c8b97a;
  padding: 0.3rem 0.5rem;
  border: 1px solid rgba(252, 211, 18, 0.2);
  background: rgba(252, 211, 18, 0.05);
  line-height: 1.4;
}

.build-card-key-timing-label {
  color: var(--wc3-gold);
  font-weight: bold;
}

.build-card-timer {
  margin-top: auto;
  padding-top: 0.75rem;
  border-top: 1px solid rgba(252, 211, 18, 0.12);
  display: flex;
  align-items: center;
  gap: 0.75rem;
}

.build-card-elapsed {
  font-size: 1.4rem;
  color: var(--wc3-gold);
  text-shadow: 0 0 8px rgba(252, 211, 18, 0.5);
  font-variant-numeric: tabular-nums;
  letter-spacing: 0.05em;
  min-width: 4ch;
}

.build-card-controls {
  display: flex;
  gap: 0.25rem;
  flex-wrap: wrap;
}

/* ── Right column: step table ── */
.build-card-steps-wrapper {
  grid-area: steps;
  display: flex;
  flex-direction: row;
  min-height: 0;
}

.build-card-steps-wrapper .glue-scrollbar-demo {
  flex-shrink: 0;
  padding: 6px 4px;
  align-self: stretch;
}

.build-card-steps-wrapper .glue-scroll-track {
  flex: 1;
  scroll-behavior: smooth;
}

.build-card-steps {
  flex: 1;
  min-width: 0;
  padding: 0;
  overflow-x: auto;
  overflow-y: auto;
  max-height: 420px;
  scrollbar-width: none;
}

.build-card-steps::-webkit-scrollbar {
  display: none;
}

.build-steps-table {
  width: 100%;
  border-collapse: separate;
  border-spacing: 0;
  font-size: 0.8rem;
}

.build-steps-table thead tr {
  border-bottom: 1px solid rgba(252, 211, 18, 0.3);
}

.build-steps-table th {
  padding: 0.35rem 0.6rem;
  text-align: left;
  color: var(--wc3-gold);
  font-size: 0.68rem;
  text-transform: uppercase;
  letter-spacing: 0.06em;
  font-weight: normal;
  border-bottom: 1px solid rgba(252, 211, 18, 0.3);
  position: sticky;
  top: 0;
  background: rgba(10, 8, 4, 0.95);
  z-index: 1;
}

.build-steps-table td {
  padding: 0.35rem 0.6rem;
  color: #dbe4ff;
  vertical-align: middle;
}

/* ── Step states ── */
.build-step-row {
  transition: opacity 0.15s ease;
  /* Reserve border space on every row so the active border doesn't shift layout */
  border: 6px solid transparent;
}

.build-step-row--past {
  opacity: 0.4;
}

.build-step-row--active {
  opacity: 1;
  background: rgba(252, 211, 18, 0.06);
}

.build-step-row--active td {
  color: var(--wc3-gold);
  text-shadow: 0 0 6px rgba(252, 211, 18, 0.35);
}

.build-step-order {
  width: 1.8rem;
  color: rgba(252, 211, 18, 0.5);
  font-size: 0.7rem;
  text-align: center;
}

.build-step-time {
  width: 3.5rem;
  font-variant-numeric: tabular-nums;
  white-space: nowrap;
}

.build-step-instruction {
  /* takes remaining space */
}

.build-steps-table th:last-child {
  text-align: right;
}

.build-step-food {
  width: 5rem;
  white-space: nowrap;
  text-align: right;
  font-variant-numeric: tabular-nums;
}

.build-step-food-icon {
  width: 12px;
  height: 12px;
  vertical-align: -1px;
  margin-right: 3px;
  image-rendering: pixelated;
}

/* ── Skill order section ── */
.skill-order-section {
  margin-top: 0.75rem;
  padding: 0.85rem 1.25rem;
}

/* ── Build Order Input Section ─────────────────────────────── */
.boi-section {
  margin-top: 0.75rem;
  padding: 1rem 1.25rem;
}

/* Form field groups — uniform column grid */
.boi-group {
  display: grid;
  grid-template-columns: repeat(3, 248px);
  justify-content: start;
  gap: 0.75rem 1.25rem;
  margin-bottom: 1rem;
  padding-bottom: 1rem;
  border-bottom: 1px solid rgba(88, 104, 158, 0.25);
}

.boi-group:last-of-type,
.boi-group:has(+ .boi-table-section) {
  border-bottom: none;
  padding-bottom: 0;
}

.boi-field {
  display: flex;
  flex-direction: column;
  gap: 0.3rem;
}

/* Make dropdowns match editbox width */
.boi-field .popup-trigger-anchor {
  width: 248px;
}

.boi-field .popup-trigger-button {
  width: 248px;
}

.boi-label {
  font-size: 0.68rem;
  color: var(--wc3-gold);
  text-transform: uppercase;
  letter-spacing: 0.06em;
  padding-left: 2px;
}

/* Steps + skill order */
.boi-table-section {
  padding-top: 1.25rem;
  padding-bottom: 1.25rem;
  border-top: 1px solid rgba(88, 104, 158, 0.25);
}

.boi-sub-title {
  margin: 0 0 0.6rem;
  font-size: 0.8rem;
  color: var(--wc3-gold);
  text-transform: uppercase;
  letter-spacing: 0.08em;
  font-weight: normal;
}

.boi-step-list {
  display: flex;
  flex-direction: column;
  gap: 0.35rem;
  margin-bottom: 0.5rem;
}

/* Step row: number | time | instruction | food | action */
.boi-step-row {
  display: grid;
  grid-template-columns: 2rem 90px 1fr 90px auto;
  align-items: center;
  gap: 0.5rem;
}

/* Smaller editboxes for time & food columns */
.boi-step-row .wc3-editbox {
  width: 100%;
}

/* Skill row: level | skill name | action */
.boi-skill-row {
  display: grid;
  grid-template-columns: 2.5rem 248px auto;
  align-items: center;
  gap: 0.5rem;
}

.boi-step-num {
  font-size: 0.78rem;
  color: var(--wc3-gold);
  text-align: center;
  font-variant-numeric: tabular-nums;
}

/* Submit row */
.boi-submit {
  display: flex;
  align-items: center;
  gap: 1rem;
}

.boi-status {
  display: inline;
}

@media (max-width: 860px) {
  .boi-group {
    grid-template-columns: repeat(2, 248px);
  }
}

@media (max-width: 600px) {
  .boi-group {
    grid-template-columns: 248px;
  }
}

.skill-order-title {
  margin: 0 0 0.85rem;
  font-size: 0.72rem;
  color: var(--wc3-gold);
  text-transform: uppercase;
  letter-spacing: 0.12em;
  font-weight: normal;
  display: flex;
  align-items: center;
  gap: 0.75rem;
  text-shadow: 0 0 6px rgba(252, 211, 18, 0.25);
}

.skill-order-title::before,
.skill-order-title::after {
  content: "";
  flex: 1;
  height: 1px;
  background: linear-gradient(
    90deg,
    transparent,
    rgba(252, 211, 18, 0.3) 20%,
    rgba(252, 211, 18, 0.3) 80%,
    transparent
  );
}

.skill-order-row {
  display: flex;
  align-items: flex-start;
  width: 100%;
}

.skill-pick {
  display: flex;
  align-items: center;
  flex: 1;
  min-width: 0;
}

.skill-pick:last-child {
  flex: 0 0 auto;
}

.skill-pick-content {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 0.35rem;
  flex-shrink: 0;
  position: relative;
  cursor: pointer;
}

.skill-tooltip {
  position: absolute;
  bottom: calc(100% + 8px);
  left: 50%;
  transform: translateX(-50%);
  width: max-content;
  min-width: 140px;
  max-width: 240px;
  z-index: 10;
  pointer-events: none;
}

.skill-pick-icon-wrapper {
  position: relative;
  width: 42px;
  height: 42px;
  border: 1px solid rgba(252, 211, 18, 0.35);
  background: rgba(0, 0, 0, 0.55);
}

.skill-pick-level {
  position: absolute;
  top: -1px;
  left: -1px;
  font-size: 0.52rem;
  color: #fcd312;
  background: rgba(0, 0, 0, 0.8);
  border: 1px solid rgba(252, 211, 18, 0.3);
  border-top: none;
  border-left: none;
  padding: 1px 4px;
  z-index: 1;
  font-weight: bold;
  letter-spacing: 0.02em;
  line-height: 1;
}

.skill-pick-icon {
  width: 100%;
  height: 100%;
  display: block;
  image-rendering: pixelated;
  object-fit: cover;
}

.skill-pick-icon--placeholder {
  width: 100%;
  height: 100%;
  background: rgba(252, 211, 18, 0.06);
}

.skill-pick-name {
  font-size: 0.62rem;
  color: #c8b97a;
  text-align: center;
  line-height: 1.2;
  white-space: nowrap;
}

.skill-pick-connector {
  flex: 1;
  height: 1px;
  min-width: 8px;
  margin: 0 0.35rem;
  margin-top: 21px;
  background: linear-gradient(
    90deg,
    rgba(252, 211, 18, 0.4),
    rgba(252, 211, 18, 0.15)
  );
}

@media (max-width: 700px) {
  .build-card {
    grid-template-columns: 1fr;
    grid-template-rows: auto auto 1fr;
    grid-template-areas:
      "header"
      "info"
      "steps";
  }

  .build-card-info {
    border-right: none;
    border-bottom: 1px solid rgba(252, 211, 18, 0.2);
  }
}

