}

.hero-card-compact-meta {
  display: flex;
  flex-direction: column;
  line-height: 1.15;
}

.hero-card-compact-meta strong {
  color: #e5ecff;
  font-size: 0.83rem;
}

.hero-card-compact-meta span {
  color: #98a8cb;
  font-size: 0.74rem;
}

.hero-card-skeleton {
  display: flex;
  align-items: center;
  gap: 10px;
  border: 1px solid #20283e;
  border-radius: 6px;
  background: #090d18;
  padding: 10px;
}

.hero-skeleton-avatar {
  width: 46px;
  height: 46px;
  border-radius: 50%;
  background: linear-gradient(90deg, #171f33 0%, #25304d 50%, #171f33 100%);
