  padding: 0;
  background: transparent;
  cursor: pointer;
  flex-shrink: 0;
}

.esc-checkbox img {
  width: 100%;
  height: 100%;
  display: block;
  position: absolute;
  inset: 0;
}

.esc-radio {
  position: relative;
  width: 24px;
  height: 24px;
  border: none;
  padding: 0;
  background: transparent;
  cursor: pointer;
  flex-shrink: 0;
}

.esc-radio img {
  width: 100%;
  height: 100%;
  display: block;
  position: absolute;
  inset: 0;
}

@media (max-width: 900px) {
  .viewport {
    padding: calc(4vw + 12px) 16px 14px;
  }

  .footer-worker-unit {
    display: none;
  }

  .token-grid {
    gap: 12px;
  }

  .token-grid-header {
    grid-template-columns: repeat(2, minmax(0, 1fr));
    gap: 6px 10px;
    margin-bottom: 0;
  }

  .token-grid-header > :first-child {
    display: none;
  }

  .token-faction-label {
    font-size: 0.64rem;
