@font-face {
  font-family: "Friz Quadrata";
  src: url("/fonts/FRIZQT__.TTF") format("truetype");
  font-weight: 400;
  font-style: normal;
  font-display: swap;
}

html,
body,
#root {
  margin: 0;
  width: 100%;
  height: 100%;
}

body {
  background: #08080f;
  color: #fff;
  overflow: hidden;
  font-family:
    "Friz Quadrata", "Palatino Linotype", "Book Antiqua", Palatino, serif;
}

:root {
  --card-bg: #111118;
  --card-border: #222233;
  --wc3-white: #ffffff;
  --wc3-gold: #fcd312;
  --wc3-dark-gold: #cca300;
  --wc3-game-cursor: auto;
}

body,
body * {
  cursor: var(--wc3-game-cursor) !important;
}

.viewport {
  position: absolute;
  inset: 0;
  overflow: auto;
  pointer-events: auto;
  padding: 24px 32px;
  padding-top: calc(4vw + 12px);
}

.viewport::-webkit-scrollbar {
  width: 8px;
}

.viewport::-webkit-scrollbar-track {
  background: #111;
}

.viewport::-webkit-scrollbar-thumb {
  background: #333;
  border-radius: 4px;
}

.tab-content {
  max-width: 1100px;
  margin: 0 auto;
}

.tab-content--showcase-flow {
  display: flex;
  flex-direction: column;
}

.tab-content--page {
  max-width: 1100px;
  margin: 0 auto;
  padding: 1rem 0.5rem;
}

.page-nav {
  margin-bottom: 0.75rem;
}

.showcase-flow-item--hero {
  order: 1;
}

.showcase-flow-item--buildorders {
  order: 2;
}

.showcase-flow-item--faction {
  order: 1;
}

.showcase-flow-item--portrait {
  order: 3;
}

.showcase-flow-item--command-card {
  order: 4;
}

.showcase-flow-item--resource-counters {
  order: 5;
}

.showcase-flow-item--bars {
  order: 6;
}

.showcase-flow-item--tooltip {
  order: 7;
}

.showcase-flow-item--unit-queue {
  order: 8;
}

.showcase-flow-item--buttons {
  order: 9;
}

.showcase-flow-item--controls {
  order: 10;
}

.showcase-flow-item--borders {
  order: 11;
}

.showcase-flow-item--tokens {
  order: 12;
}

.showcase-flow-item--a11y {
  order: 13;
}

.showcase-flow-item--bundle {
  order: 14;
}

.showcase-flow-item--faq {
  order: 15;
}

.showcase-flow-item--footer {
  order: 16;
}

.section-card {
  background: var(--card-bg);
  border: 1px solid var(--card-border);
  border-radius: 8px;
  padding: 24px;
  margin-bottom: 24px;
}

.viewport--race-card-borders .section-card {
  border: 18px solid transparent;
  border-radius: 0;
  border-image-source: var(--section-card-border-image);
  border-image-slice: 64;
  border-image-width: 1;
  border-image-repeat: round;
}

.section-card h2 {
  margin: 0 0 8px;
  color: var(--wc3-white);
  font-size: 1.45rem;
  text-shadow: 1px 1px 0 rgba(0, 0, 0, 0.92);
}

.section-card h3 {
  margin: 0 0 8px;
  color: var(--wc3-gold);
  font-size: 1.25rem;
  text-shadow: 1px 1px 0 rgba(0, 0, 0, 0.9);
}

.section-card .section-desc {
  margin: 0 0 14px;
  color: #9aa4c0;
  line-height: 1.5;
}

.library-intro {
  margin: 0;
  color: #d3ddfb;
  line-height: 1.42;
}

.button-showcase-grid {
  display: flex;
  flex-direction: column;
}

.button-showcase-section {
  padding: 18px 0 10px;
  border-top: 1px solid rgba(88, 104, 158, 0.45);
}

.button-showcase-section:first-child {
  padding-top: 0;
  border-top: none;
}

.button-showcase-title {
  margin: 0 0 4px;
  color: #e2e9ff;
  font-size: 0.98rem;
}

.button-showcase-desc {
  margin: 0 0 12px;
  color: #7b818d;
  font-size: 0.85rem;
  line-height: 1.5;
}

.button-preview-row {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
  justify-content: center;
  align-items: flex-end;
}

.button-preview-col {
  display: flex;
  flex-direction: column;
  align-items: center;
  text-align: center;
}

.button-preview-row--textarea {
  width: 100%;
}

.button-preview-col--textarea {
  width: min(100%, 560px);
  align-items: stretch;
}

.button-preview-col--textarea .button-state-label {
  text-align: center;
}

.top-tab-preview {
  position: relative;
  width: 120px;
  height: 32px;
  border: none;
  background: transparent;
  padding: 0;
  cursor: pointer;
  font-family: inherit;
}

.top-tab-preview span {
  display: inline-flex;
  width: 100%;
  height: 100%;
  align-items: center;
  justify-content: center;
  font-size: clamp(12px, 1.25vw, 18px);
  line-height: 1;
  white-space: nowrap;
  user-select: none;
  text-shadow: 1px 1px 0 rgba(0, 0, 0, 0.95);
}

.button-state-label {
  margin-top: 3px;
  font-size: 0.74rem;
  color: #adbce4;
}

.glue-screen-showcase {
  display: flex;
  justify-content: center;
  flex-wrap: wrap;
  gap: 16px;
}

.glue-screen-button {
  position: relative;
  width: 260px;
  height: 48px;
  border: none;
  background: transparent;
  padding: 0;
  cursor: pointer;
  color: var(--wc3-gold);
  font-family: inherit;
  font-size: 1rem;
  text-shadow: 1px 1px 0 rgba(0, 0, 0, 0.95);
}

.glue-screen-button:disabled {
  cursor: default;
}

.glue-screen-button > span {
  position: relative;
  z-index: 2;
  display: flex;
  width: 100%;
  height: 100%;
  align-items: center;
  justify-content: center;
}

.glue-screen-canvas {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  display: block;
  image-rendering: pixelated;
}

.menu-button-showcase {
  display: flex;
  justify-content: center;
  flex-wrap: wrap;
  gap: 16px;
}

.menu-button-shell {
  position: relative;
  width: 290px;
  height: 85px;
  overflow: hidden;
}

.menu-button-frame {
  position: absolute;
  top: 0;
  left: -50px;
  width: 340px;
  height: 100%;
}

.menu-button-inner {
  position: absolute;
  top: 25.8%;
  right: 5.5%;
  bottom: 25.8%;
  left: 12.5%;
  border: none;
  background: transparent;
  padding: 0;
  cursor: pointer;
  color: var(--wc3-gold);
  font-family: inherit;
  font-size: 1.02rem;
  text-shadow: 1px 1px 0 rgba(0, 0, 0, 0.95);
}

.menu-button-inner--single {
  top: 24.4%;
  right: 14.66%;
  bottom: 27.15%;
  left: 12.5%;
}

.menu-button-bg,
.menu-button-border,
.menu-button-highlight {
  position: absolute;
  inset: 0;
}

.menu-button-bg {
  background-repeat: repeat;
  background-size: 32px 32px;
}

.menu-button-border {
  background-repeat: no-repeat;
  background-size: 100% 100%;
}

.menu-button-highlight {
  background-repeat: no-repeat;
  background-size: 100% 100%;
  transition: opacity 80ms linear;
  mix-blend-mode: screen;
}

.menu-button-label {
  position: relative;
  z-index: 2;
  display: flex;
  width: 100%;
  height: 100%;
  align-items: center;
  justify-content: center;
}

.button-hotkey {
  color: var(--wc3-white);
}

.menu-button-canvas {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  display: block;
  image-rendering: pixelated;
}

.menu-frame-variant-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(248px, 1fr));
  column-gap: 8px;
  row-gap: 20px;
  justify-items: center;
  align-items: flex-end;
}

.menu-frame-variant-grid .button-preview-col {
  width: 100%;
}

.menu-frame-variant-grid .menu-frame-variant-shell {
  margin: 0 auto;
}

.menu-frame-variant-shell {
  position: relative;
  overflow: hidden;
}

.menu-frame-variant-image {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  object-fit: fill;
  image-rendering: pixelated;
  pointer-events: none;
}

.menu-frame-variant-inner {
  z-index: 2;
  font-size: 0.92rem;
}

.menu-frame-variant-inner--tiny {
  top: 28%;
  right: 9%;
  bottom: 26%;
  left: 15%;
  font-size: 0.84rem;
}

.menu-frame-variant-meta {
  margin-top: 2px;
  color: #8e9ab7;
  font-size: 0.66rem;
  line-height: 1.2;
}

.option-button-row {
  display: flex;
  gap: 10px;
  flex-wrap: wrap;
  justify-content: center;
}

.esc-option-preview {
  position: relative;
  width: 208px;
  height: 40px;
  border: none;
  background: transparent;
  padding: 0;
  cursor: pointer;
  color: var(--wc3-gold);
  font-family: inherit;
  font-size: 0.92rem;
  text-shadow: 1px 1px 0 rgba(0, 0, 0, 0.95);
}

.esc-option-canvas {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  display: block;
  image-rendering: pixelated;
}

.esc-option-label {
  position: relative;
  z-index: 2;
  display: flex;
  width: 100%;
  height: 100%;
  align-items: center;
  justify-content: center;
}

.esc-option-label-disabled {
  color: #808080;
}

.esc-option-preview:disabled {
  cursor: default;
}

.glue-small-button {
  position: relative;
  width: 146px;
  height: 40px;
  border: none;
  background: transparent;
  padding: 0;
  cursor: pointer;
  color: var(--wc3-gold);
  font-family: inherit;
  font-size: 0.95rem;
  text-shadow: 1px 1px 0 rgba(0, 0, 0, 0.95);
}

.glue-small-button:disabled {
  cursor: default;
}

.glue-small-button > span {
  position: relative;
  z-index: 2;
  display: flex;
  width: 100%;
  height: 100%;
  align-items: center;
  justify-content: center;
}

.campaign-button {
  position: relative;
  width: 250px;
  height: 48px;
  border: none;
  background: transparent;
  padding: 0;
  cursor: pointer;
  color: var(--wc3-gold);
  font-family: inherit;
  font-size: 1rem;
  text-shadow: 1px 1px 0 rgba(0, 0, 0, 0.95);
}

.campaign-button:disabled {
  cursor: default;
}

.campaign-button > span {
  position: relative;
  z-index: 2;
  display: flex;
  width: 100%;
  height: 100%;
  align-items: center;
  justify-content: center;
}

.popup-trigger-button {
  position: relative;
  display: flex;
  align-items: center;
  justify-content: space-between;
  width: 220px;
  height: 36px;
  border: none;
  background: transparent;
  color: var(--wc3-gold);
  font-family: inherit;
  font-size: 0.84rem;
  line-height: 1;
  padding: 0 12px;
  cursor: pointer;
  text-shadow: 1px 1px 0 rgba(0, 0, 0, 0.95);
}

.popup-trigger-button:disabled {
  cursor: default;
}

.popup-trigger-canvas {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  display: block;
  image-rendering: pixelated;
  pointer-events: none;
}

.popup-title-text,
.popup-arrow-icon {
  position: relative;
  z-index: 2;
}

.popup-title-text {
  flex: 1;
  text-align: left;
  color: var(--wc3-gold);
}

.popup-title-text-disabled {
  color: #808080;
}

.popup-arrow-icon {
  width: 16px;
  height: 16px;
  image-rendering: pixelated;
}

.popup-trigger-anchor {
  position: relative;
  width: 220px;
}

.popup-menu-demo {
  position: absolute;
  top: calc(100% + 3px);
  left: 0;
  z-index: 8;
  width: 220px;
  padding: 10px 5px;
  box-shadow: 0 4px 14px rgba(0, 0, 0, 0.55);
  text-align: left;
  overflow: hidden;
}

.popup-menu-canvas {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  display: block;
  image-rendering: pixelated;
  pointer-events: none;
}

.popup-menu-option {
  position: relative;
  z-index: 2;
  width: 100%;
  border: none;
  background: transparent;
  text-align: left;
  padding: 5px 12px;
  font-size: 0.82rem;
  color: #ffffff;
  font-family: inherit;
  cursor: pointer;
  text-shadow: 1px 1px 0 rgba(0, 0, 0, 0.95);
}

.popup-menu-option:hover {
  color: var(--wc3-gold);
  background: rgba(0, 0, 0, 0.22);
}

.popup-menu-option[aria-selected="true"] {
  color: var(--wc3-gold);
  background: transparent;
}

.wc3-editbox {
  position: relative;
  width: 248px;
  height: 46px;
  display: block;
}

.wc3-editbox--bnet {
  height: 44px;
}

.wc3-editbox-canvas {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  display: block;
  image-rendering: pixelated;
  pointer-events: none;
}

.wc3-editbox input {
  position: relative;
  z-index: 2;
  width: 100%;
  height: 100%;
  border: none;
  background: transparent;
  color: #f2f5ff;
  padding: 0 12px;
  font-family: inherit;
  font-size: 0.88rem;
  text-shadow: none;
  outline: none;
}

.wc3-editbox input::selection {
  background: rgba(255, 212, 18, 0.35);
}

.wc3-editbox--disabled {
  opacity: 0.68;
}

.wc3-editbox--disabled input {
  color: #808080;
  cursor: default;
}

.glue-scrollbar-demo {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 4px;
}

.glue-scroll-arrow {
  width: 16px;
  height: 16px;
  border: none;
  background: transparent;
  padding: 0;
  cursor: pointer;
}

.glue-scroll-arrow img {
  width: 100%;
  height: 100%;
  display: block;
  image-rendering: pixelated;
  pointer-events: none;
}

.glue-scroll-arrow:disabled {
  cursor: default;
  opacity: 0.68;
}

.glue-scroll-track {
  position: relative;
  width: 18px;
  height: 132px;
}

.glue-scroll-track-canvas {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  display: block;
  image-rendering: pixelated;
  pointer-events: none;
}

.glue-scroll-thumb {
  position: absolute;
  left: 50%;
  width: 16px;
  height: 16px;
  transform: translate(-50%, -50%);
  background-repeat: no-repeat;
  background-size: 100% 100%;
  image-rendering: pixelated;
  pointer-events: none;
}

.glue-scroll-track input[type="range"] {
  position: absolute;
  inset: 0;
  margin: 0;
  opacity: 0;
  writing-mode: vertical-lr;
  cursor: pointer;
}

.glue-scrollbar-demo--disabled {
  opacity: 0.76;
}

.esc-textarea-demo {
  display: flex;
  align-items: stretch;
  gap: 8px;
  width: min(100%, 528px);
}

.esc-textarea-shell {
  position: relative;
  flex: 1 1 auto;
  min-width: 0;
  height: 150px;
  overflow: hidden;
}

.esc-textarea-canvas {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  display: block;
  image-rendering: pixelated;
  pointer-events: none;
}

.esc-textarea-mask {
  position: absolute;
  inset: 11px 15px;
  overflow: hidden;
  z-index: 2;
}

.esc-textarea-content {
  position: absolute;
  inset: 0;
  padding: 2px 10px 2px 8px;
  z-index: 2;
  color: #d8def5;
  font-size: 0.78rem;
  text-align: left;
  white-space: pre;
  text-shadow: 1px 1px 0 rgba(0, 0, 0, 0.92);
  will-change: transform;
}

.esc-textarea-content > div {
  height: 18px;
}

.esc-textarea-scroll {
  position: relative;
  flex: 0 0 20px;
  width: 20px;
  height: 150px;
}

.esc-textarea-scroll-canvas {
  position: absolute;
  inset: 8px 0;
  width: 100%;
  height: calc(100% - 16px);
  display: block;
  image-rendering: pixelated;
  pointer-events: none;
}

.esc-textarea-scroll-thumb {
  position: absolute;
  top: 18%;
  left: 50%;
  width: 18px;
  height: 18px;
  transform: translate(-50%, -50%);
  background-repeat: no-repeat;
  background-size: 100% 100%;
  image-rendering: pixelated;
  pointer-events: none;
}

.esc-textarea-scroll input[type="range"] {
  position: absolute;
  inset: 8px 0;
  margin: 0;
  opacity: 0;
  writing-mode: vertical-lr;
  cursor: pointer;
}

.wc3-listbox-demo {
  display: flex;
  align-items: stretch;
  gap: 8px;
}

.wc3-listbox-shell {
  position: relative;
  width: 248px;
  height: 136px;
  overflow: hidden;
}

.wc3-listbox-canvas {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  display: block;
  image-rendering: pixelated;
  pointer-events: none;
}

.wc3-listbox-mask {
  position: absolute;
  inset: 16px;
  overflow: hidden;
  z-index: 2;
}

.wc3-listbox-items {
  position: absolute;
  inset: 0;
  padding: 2px 0;
  z-index: 2;
  text-align: left;
  will-change: transform;
}

.wc3-listbox-item {
  display: block;
  width: 100%;
  height: 20px;
  border: none;
  padding: 0 12px;
  background: transparent;
  color: #dbe4ff;
  font-family: inherit;
  font-size: 0.82rem;
  text-align: left;
  text-shadow: 1px 1px 0 rgba(0, 0, 0, 0.95);
  cursor: pointer;
}

.wc3-listbox-item:hover {
  color: var(--wc3-gold);
  background: rgba(255, 255, 255, 0.08);
}

.wc3-listbox-item--selected {
  color: var(--wc3-gold);
  background: rgba(255, 255, 255, 0.12);
}

.wc3-listbox-scrollbar {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 4px;
}

.wc3-listbox-scroll-arrow {
  width: 16px;
  height: 16px;
  border: none;
  background: transparent;
  padding: 0;
  cursor: pointer;
}

.wc3-listbox-scroll-arrow img {
  width: 100%;
  height: 100%;
  display: block;
  image-rendering: pixelated;
  pointer-events: none;
}

.wc3-listbox-scroll {
  position: relative;
  width: 18px;
  height: 96px;
}

.wc3-listbox-scroll-canvas {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  display: block;
  image-rendering: pixelated;
  pointer-events: none;
}

.wc3-listbox-scroll-thumb {
  position: absolute;
  left: 50%;
  width: 16px;
  height: 16px;
  transform: translate(-50%, -50%);
  background-repeat: no-repeat;
  background-size: 100% 100%;
  image-rendering: pixelated;
  pointer-events: none;
}

.wc3-listbox-scroll input[type="range"] {
  position: absolute;
  inset: 0;
  margin: 0;
  opacity: 0;
  writing-mode: vertical-lr;
  cursor: pointer;
}

.wc3-bar {
  position: relative;
  width: 100%;
  margin: 0 auto;
  overflow: hidden;
}

.wc3-bar + .wc3-bar {
  margin-top: 8px;
}

.wc3-bar--large {
  height: 20px;
}

.wc3-bar--unit {
  width: min(
    100%,
    182.93px
  ); /* HPBarConsoleSmall/ManaBarConsoleSmall frame ratio: 0.04065 / 0.004 */
  height: 18px;
}

.wc3-bar--compact {
  width: min(
    100%,
    157.14px
  ); /* XpBarConsole/TimerBar frame ratio: 0.17776 / 0.01810 */
  height: 16px;
}

.wc3-bar--build {
  width: min(
    100%,
    163.7px
  ); /* BuildProgressBar frame ratio: 0.10538 / 0.01030 */
}

.wc3-bar-track,
.wc3-bar-border {
  position: absolute;
  inset: 0;
  background-repeat: no-repeat;
  background-size: 100% 100%;
  image-rendering: auto;
  pointer-events: none;
}

.wc3-bar-canvas {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  display: block;
  image-rendering: auto;
  pointer-events: none;
}

.wc3-bar-fill-wrap {
  position: absolute;
  inset: 0 auto 0 0;
  overflow: hidden;
  transition: width 620ms ease;
}

.wc3-bar-fill,
.wc3-bar-highlight {
  position: absolute;
  inset: 0;
  background-repeat: no-repeat;
  background-size: 100% 100%;
  image-rendering: auto;
  pointer-events: none;
}

.wc3-bar-fill--health {
  filter: saturate(1.18);
}

.wc3-bar-fill--mana {
  filter: saturate(1.2) hue-rotate(6deg);
}

.wc3-bar-fill--progress {
  filter: saturate(1.05);
}

.wc3-bar-fill--build {
  filter: saturate(1.12) hue-rotate(-9deg);
}

.wc3-bar-highlight {
  mix-blend-mode: screen;
  opacity: 0.62;
}

.wc3-bar-segments {
  position: absolute;
  inset: 2px;
  pointer-events: none;
  background-image: repeating-linear-gradient(
    to right,
    rgba(0, 0, 0, 0.38) 0 1px,
    rgba(0, 0, 0, 0) 1px 10%
  );
  opacity: 0.55;
}

.wc3-bar-text {
  position: absolute;
  inset: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  color: #f6f8ff;
  font-size: 0.74rem;
  line-height: 1;
  text-shadow: 1px 1px 0 rgba(0, 0, 0, 0.95);
  pointer-events: none;
}

.wc3-bar--compact .wc3-bar-text {
  font-size: 0.68rem;
}

.loading-preview {
  display: flex;
  justify-content: center;
}

.loading-bar-composite {
  position: relative;
  width: min(100%, 640px);
  aspect-ratio: 8.007 / 1; /* LoadBar.mdx border geoset ratio: 0.45804 / 0.05720 */
  height: auto;
  max-height: 80px;
  overflow: visible;
}

.loading-bar-composite .lb-track {
  position: absolute;
  overflow: hidden;
}

.loading-bar-composite .lb-bg {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  background-repeat: repeat-x;
  background-size: auto 100%;
  image-rendering: auto;
}

.loading-bar-composite .lb-fill {
  position: absolute;
  left: 0;
  top: 0;
  bottom: 0;
  width: 0%;
  background-repeat: repeat-x;
  background-size: auto 100%;
  image-rendering: auto;
  transition: width 90ms linear;
  will-change: width;
}

.loading-bar-composite .lb-border,
.loading-bar-composite .lb-glass {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  display: block;
  object-fit: fill;
  pointer-events: none;
}

.loading-bar-composite .lb-border {
  z-index: 1;
}

.loading-bar-composite .lb-glass {
  z-index: 2;
  opacity: 1;
}

.loading-bar-composite .lb-glow {
  position: absolute;
  display: block;
  object-fit: fill;
  z-index: 4;
  mix-blend-mode: screen;
  mix-blend-mode: plus-lighter;
  pointer-events: none;
  transition:
    width 90ms linear,
    opacity 90ms linear;
}

.loading-bar-composite .lb-text {
  position: absolute;
  inset: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 5;
  color: #f6f8ff;
  font-size: 0.78rem;
  line-height: 1;
  text-shadow: 1px 1px 0 rgba(0, 0, 0, 0.95);
  pointer-events: none;
}

.esc-slider-demo {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 6px;
}

.esc-slider-value {
  color: #d8def5;
  font-size: 0.82rem;
}

.esc-slider-track {
  position: relative;
  width: 220px;
  height: 20px;
}

.esc-slider-canvas {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  display: block;
  image-rendering: pixelated;
  pointer-events: none;
}

.esc-slider-knob {
  position: absolute;
  top: 50%;
  width: 28px;
  height: 28px;
  transform: translate(-50%, -50%);
  background-repeat: no-repeat;
  background-size: 100% 100%;
  image-rendering: pixelated;
  pointer-events: none;
}

.esc-slider-track input[type="range"] {
  position: absolute;
  inset: 0;
  opacity: 0;
  margin: 0;
  cursor: pointer;
}

.cmd-overlay-button {
  position: relative;
  width: 48px;
  height: 48px;
  border: 2px solid #1a1a2e;
  border-radius: 2px;
  overflow: hidden;
  background: #000;
}

.cmd-overlay-button--showcase {
  width: 64px;
  height: 64px;
}

.cmd-overlay-base,
.cmd-overlay-layer,
.cmd-overlay-level {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  display: block;
  image-rendering: pixelated;
  pointer-events: none;
}

.cmd-overlay-add {
  mix-blend-mode: screen;
}

/* Loading Screen */
.loading-screen {
  position: fixed;
  inset: 0;
  z-index: 1000;
  display: flex;
  align-items: center;
  justify-content: center;
  background: #05080f;
  transition: opacity 400ms ease;
}

.loading-screen--fading {
  opacity: 0;
  pointer-events: none;
}

.loading-screen-bg {
  position: absolute;
  inset: 0;
  /* Placeholder gradient — swap for a WC3 loading screen image later:
     background: url("/loading/loading-screen-bg.jpg") center / cover no-repeat; */
  background: radial-gradient(
    ellipse at 50% 40%,
    #1a2440 0%,
    #0a0e1a 70%,
    #05080f 100%
  );
}

.loading-screen-content {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 24px;
  width: min(560px, 90vw);
}

.loading-screen-logo {
  width: min(340px, 70vw);
  height: auto;
  filter: drop-shadow(0 2px 12px rgba(0, 0, 0, 0.8));
  user-select: none;
  -webkit-user-drag: none;
}

.loading-screen-bar-wrap {
  width: 100%;
}

.loading-screen-label {
  margin: 0;
  color: #7c8fb5;
  font-size: 0.82rem;
  letter-spacing: 0.08em;
  text-transform: uppercase;
}

/* Hero Section */
.hero-section {
  text-align: center;
  padding: 24px 24px 32px;
  margin-bottom: 24px;
}

.hero-content {
  position: relative;
}

.hero-logo {
  display: block;
  margin: 0 auto 8px;
  width: min(420px, 60vw);
  height: auto;
  filter: drop-shadow(0 2px 6px rgba(0, 0, 0, 0.6));
  user-select: none;
  -webkit-user-drag: none;
}

.hero-subtitle {
  margin: 0 0 12px;
  color: #d3ddfb;
  font-size: 1.3rem;
}

.hero-description {
  margin: 0 0 24px;
  color: #9aa4c0;
  font-size: 0.95rem;
  line-height: 1.5;
  max-width: 600px;
  margin-left: auto;
  margin-right: auto;
}

.hero-description strong {
  color: #eceff7;
}

.hero-cta-row {
  display: flex;
  gap: 12px;
  justify-content: center;
  margin-bottom: 16px;
}

.hero-cta-row--components {
  align-items: center;
  flex-wrap: wrap;
  gap: 6px;
}

.home-cta-row {
  display: flex;
  gap: 16px;
  justify-content: center;
  margin-bottom: 16px;
}

.home-cta-row .esc-option-preview {
  width: 170px;
  height: 44px;
}

.hero-get-started-btn {
  width: 150px;
  height: 40px;
  flex: 0 0 150px;
  margin: 0;
}

.hero-install-editbox {
  width: 150px;
  height: 40px;
  flex: 0 0 150px;
  margin: 0;
  cursor: pointer;
}

.hero-install-editbox input {
  text-align: center;
  color: var(--wc3-gold);
  font-family:
    "Friz Quadrata", "Palatino Linotype", "Book Antiqua", Palatino, serif;
  font-size: 0.9rem;
  line-height: 1;
  cursor: pointer;
  padding: 0 8px;
}

.hero-footer {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 8px;
  margin-top: 4px;
}

.hero-footer-divider {
  width: 120px;
  height: 1px;
  background: linear-gradient(
    90deg,
    transparent 0%,
    var(--wc3-gold, #c6a44e) 50%,
    transparent 100%
  );
  opacity: 0.4;
}

.hero-footer-quote {
  margin: 0;
  color: #8a94b8;
  font-size: 0.86rem;
  font-style: italic;
  font-family:
    "Friz Quadrata", "Palatino Linotype", "Book Antiqua", Palatino, serif;
  text-shadow: 1px 1px 0 rgba(0, 0, 0, 0.7);
}

.hero-footer-version {
  color: #4e5678;
  font-size: 0.72rem;
  letter-spacing: 0.08em;
  text-transform: uppercase;
}

.hero-features {
  display: flex;
  gap: 12px;
  justify-content: center;
  margin: 0 0 20px;
  flex-wrap: wrap;
}

.hero-feature-tile {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 2px;
  background: rgba(20, 28, 50, 0.7);
  border: 1px solid #2b3a60;
  border-radius: 4px;
  padding: 10px 20px;
  min-width: 90px;
}

.hero-feature-value {
  color: var(--wc3-gold);
  font-size: 1.4rem;
  font-family:
    "Friz Quadrata", "Palatino Linotype", "Book Antiqua", Palatino, serif;
  line-height: 1;
}

.hero-feature-label {
  color: #7c8fb5;
  font-size: 0.74rem;
  text-transform: uppercase;
  letter-spacing: 0.06em;
}

.hero-races {
  display: flex;
  gap: 10px;
  justify-content: center;
  margin: 0 0 20px;
  flex-wrap: wrap;
}

.hero-race-badge {
  display: flex;
  align-items: center;
  gap: 6px;
  background: rgba(15, 22, 42, 0.75);
  border: 1px solid #243050;
  border-radius: 3px;
  padding: 5px 12px;
  color: #b8c8e8;
  font-size: 0.82rem;
}

.hero-race-badge-icon {
  width: 20px;
  height: 20px;
  object-fit: contain;
  image-rendering: pixelated;
}

/* Faction Preview */
.faction-preview-section .section-desc {
  text-align: center;
  font-style: italic;
}

.faction-preview {
  display: grid;
  grid-template-columns: repeat(4, minmax(0, 1fr));
  gap: 10px;
}

.faction-preview-card {
  background: transparent;
  border: none;
  border-radius: 0;
  padding: 0;
  text-align: left;
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.faction-preview-label {
  color: var(--wc3-dark-gold);
  font-size: 0.85rem;
  margin-bottom: 2px;
  text-align: center;
}

.faction-preview-samples {
  display: flex;
  flex-direction: column;
  gap: 6px;
  align-items: center;
}

.faction-preview-control {
  width: min(100%, 192px);
  max-width: 192px;
}

.faction-preview-control-label {
  margin: 0 0 4px;
  color: #7982a0;
  font-size: 0.64rem;
  letter-spacing: 0.06em;
  text-transform: uppercase;
}

.faction-preview-option-button {
  width: 192px;
  height: 36px;
}

.faction-preview-slider-demo {
  align-items: flex-start;
  gap: 3px;
}

.faction-preview-slider-track {
  width: 192px;
}

@media (max-width: 980px) {
  .faction-preview {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }
}

@media (max-width: 640px) {
  .button-preview-col--textarea {
    width: 100%;
  }

  .faction-preview {
    grid-template-columns: 1fr;
  }
}

/* Install Section */
.install-section .code-block {
  margin-bottom: 12px;
}

.code-block {
  background: #0a0a14;
  border: 1px solid #222233;
  border-radius: 6px;
  padding: 14px 18px;
  overflow-x: auto;
}

.code-block code,
.code-block pre {
