  color: #7b818d;
  font-size: 0.72rem;
  text-transform: uppercase;
  letter-spacing: 0.04em;
}

.token-grid-row {
  display: grid;
  grid-template-columns: 164px repeat(4, 1fr);
  gap: 6px;
  align-items: center;
}

.token-name {
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.token-name code {
