  height: 16px;
  width: var(--bundle-bar-width);
  background: #0a0a14;
  border-radius: 2px;
  overflow: hidden;
}

.bundle-chart-bar-canvas {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  display: block;
  image-rendering: auto;
  pointer-events: none;
}

.bundle-chart-size {
  color: #7b818d;
  font-size: 0.78rem;
  font-family:
    "Friz Quadrata", "Palatino Linotype", "Book Antiqua", Palatino, serif;
}

/* FAQ */
.faq-section h3 {
  margin-bottom: 14px;
}

.faq-list {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.faq-item {
