@font-face {
  font-family: "Friz Quadrata";
  src: url("/fonts/FRIZQT__.TTF") format("truetype");
  font-weight: 400;
  font-style: normal;
  font-display: swap;
}

html,
body,
#root {
  margin: 0;
  width: 100%;
  height: 100%;
}

body {
  background: #08080f;
  color: #fff;
  overflow: hidden;
  font-family:
    "Friz Quadrata", "Palatino Linotype", "Book Antiqua", Palatino, serif;
}

:root {
  --card-bg: #111118;
  --card-border: #222233;
  --wc3-white: #ffffff;
  --wc3-gold: #fcd312;
  --wc3-dark-gold: #cca300;
  --wc3-game-cursor: auto;
}

body,
body * {
  cursor: var(--wc3-game-cursor) !important;
}

.viewport {
  position: absolute;
  inset: 0;
  overflow: auto;
  pointer-events: auto;
  padding: 24px 32px;
  padding-top: calc(4vw + 12px);
}

.viewport::-webkit-scrollbar {
  width: 8px;
}

.viewport::-webkit-scrollbar-track {
  background: #111;
}

.viewport::-webkit-scrollbar-thumb {
  background: #333;
  border-radius: 4px;
}

.tab-content {
  max-width: 1100px;
  margin: 0 auto;
}

.tab-content--showcase-flow {
  display: flex;
  flex-direction: column;
}

.tab-content--page {
  max-width: 1100px;
  margin: 0 auto;
  padding: 1rem 0.5rem;
}

.page-nav {
  margin-bottom: 0.75rem;
}

.showcase-flow-item--hero {
  order: 1;
}

.showcase-flow-item--buildorders {
  order: 2;
}

.showcase-flow-item--faction {
  order: 1;
}

.showcase-flow-item--portrait {
  order: 3;
}

.showcase-flow-item--command-card {
  order: 4;
}

.showcase-flow-item--resource-counters {
  order: 5;
}

.showcase-flow-item--bars {
  order: 6;
}

.showcase-flow-item--tooltip {
  order: 7;
}

.showcase-flow-item--unit-queue {
  order: 8;
}

.showcase-flow-item--buttons {
  order: 9;
}

.showcase-flow-item--controls {
  order: 10;
}

.showcase-flow-item--borders {
  order: 11;
}

.showcase-flow-item--tokens {
  order: 12;
}

.showcase-flow-item--a11y {
  order: 13;
}

.showcase-flow-item--bundle {
  order: 14;
}

.showcase-flow-item--faq {
  order: 15;
}

.showcase-flow-item--footer {
  order: 16;
}

.section-card {
  background: var(--card-bg);
  border: 1px solid var(--card-border);
  border-radius: 8px;
  padding: 24px;
  margin-bottom: 24px;
}

.viewport--race-card-borders .section-card {
  border: 18px solid transparent;
  border-radius: 0;
  border-image-source: var(--section-card-border-image);
  border-image-slice: 64;
  border-image-width: 1;
  border-image-repeat: round;
}

.section-card h2 {
  margin: 0 0 8px;
  color: var(--wc3-white);
  font-size: 1.45rem;
  text-shadow: 1px 1px 0 rgba(0, 0, 0, 0.92);
}

.section-card h3 {
  margin: 0 0 8px;
  color: var(--wc3-gold);
  font-size: 1.25rem;
  text-shadow: 1px 1px 0 rgba(0, 0, 0, 0.9);
}

.section-card .section-desc {
  margin: 0 0 14px;
  color: #9aa4c0;
  line-height: 1.5;
}

.library-intro {
  margin: 0;
  color: #d3ddfb;
  line-height: 1.42;
}

.button-showcase-grid {
  display: flex;
  flex-direction: column;
}

.button-showcase-section {
  padding: 18px 0 10px;
  border-top: 1px solid rgba(88, 104, 158, 0.45);
}

.button-showcase-section:first-child {
  padding-top: 0;
  border-top: none;
}

.button-showcase-title {
  margin: 0 0 4px;
  color: #e2e9ff;
  font-size: 0.98rem;
}

.button-showcase-desc {
  margin: 0 0 12px;
  color: #7b818d;
  font-size: 0.85rem;
  line-height: 1.5;
}

.button-preview-row {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
  justify-content: center;
  align-items: flex-end;
}

.button-preview-col {
  display: flex;
  flex-direction: column;
  align-items: center;
  text-align: center;
}

.button-preview-row--textarea {
  width: 100%;
}

.button-preview-col--textarea {
  width: min(100%, 560px);
  align-items: stretch;
}

.button-preview-col--textarea .button-state-label {
  text-align: center;
}

.top-tab-preview {
  position: relative;
  width: 120px;
  height: 32px;
  border: none;
  background: transparent;
  padding: 0;
  cursor: pointer;
  font-family: inherit;
}

.top-tab-preview span {
  display: inline-flex;
  width: 100%;
  height: 100%;
  align-items: center;
  justify-content: center;
  font-size: clamp(12px, 1.25vw, 18px);
  line-height: 1;
  white-space: nowrap;
  user-select: none;
  text-shadow: 1px 1px 0 rgba(0, 0, 0, 0.95);
}

.button-state-label {
  margin-top: 3px;
  font-size: 0.74rem;
  color: #adbce4;
}

.glue-screen-showcase {
  display: flex;
  justify-content: center;
  flex-wrap: wrap;
  gap: 16px;
}

.glue-screen-button {
  position: relative;
  width: 260px;
  height: 48px;
  border: none;
  background: transparent;
  padding: 0;
  cursor: pointer;
  color: var(--wc3-gold);
  font-family: inherit;
  font-size: 1rem;
  text-shadow: 1px 1px 0 rgba(0, 0, 0, 0.95);
}

.glue-screen-button:disabled {
  cursor: default;
}

.glue-screen-button > span {
  position: relative;
  z-index: 2;
  display: flex;
  width: 100%;
  height: 100%;
  align-items: center;
  justify-content: center;
}

.glue-screen-canvas {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  display: block;
  image-rendering: pixelated;
}

.menu-button-showcase {
  display: flex;
  justify-content: center;
  flex-wrap: wrap;
  gap: 16px;
}

.menu-button-shell {
  position: relative;
  width: 290px;
  height: 85px;
  overflow: hidden;
