function useHeroIconUrl(heroName: string): string {
  const [iconUrl, setIconUrl] = useState("");
  useEffect(() => {
    let cancelled = false;
    const file = HERO_ICONS[heroName];
    if (!file) return;
    void loadBlpDataUrl(`./buttons/command/${file}.blp`).then((url) => {
      if (!cancelled) setIconUrl(url);
    });
    return () => { cancelled = true; };
  }, [heroName]);
  return iconUrl;
}

function HeroIcon({ heroName }: { heroName: string }) {
  const iconUrl = useHeroIconUrl(heroName);
  if (!iconUrl) return null;
  return (
    <img src={iconUrl} alt={heroName} title={heroName} className="build-card-hero-icon" />
  );
}

function InfoHeroRow({ heroName }: { heroName: string }) {
  const iconUrl = useHeroIconUrl(heroName);
  return (
    <div className="info-hero-row">
      {iconUrl
        ? <img src={iconUrl} alt={heroName} className="info-hero-icon" />
        : <div className="info-hero-icon info-hero-icon--placeholder" />
      }
      <span className="info-hero-name">{heroName}</span>
    </div>
  );
}

