toolUseResult.originalFile:
import { useCallback, useEffect, useRef, useState } from "react";
import {
  useTimerRunning,
  useElapsedSeconds,
  startTimer,
  pauseTimer,
  resetTimer,
} from "../../state/timer";
import { useCurrentRace, setCurrentRace } from "../../state/race";
import type { Race } from "../../lib/types";
import GlueSmallButton from "../GlueSmallButton";
import GlueBorderedButton from "../GlueBorderedButton";
import GlueDropdown from "../GlueDropdown";
import GlueScrollbar from "../GlueScrollbar";
import { useBuildOrders, importBuilds } from "../../state/buildOrders";
import type { BuildOrder } from "../../data/buildOrders";

const RACES: Race[] = ["Human", "Orc", "NightElf", "Undead"];
const RACE_LABELS: Record<Race, string> = {
  Human: "Human",
  Orc: "Orc",
  NightElf: "Night Elf",
  Undead: "Undead",
};
import {
  loadBlpDataUrl,
  loadDataUrlImage,
  composeBorderImageFromAtlas,
} from "../../utils/glueButton";
import { resolveIconPath } from "../SkillOrderSection";
import SkillTooltip from "../SkillTooltip";
import BuildOrderInputSection from "./BuildOrderInputSection";
import FooterSection from "./FooterSection";

function formatTime(seconds: number): string {
  const m = Math.floor(seconds / 60);
  const s = seconds % 60;
  return `${m}:${s.toString().padStart(2, "0")}`;
}

function parseStepTime(time: string): number {
  const [m, s] = time.split(":").map(Number);
  return m * 60 + (s ?? 0);
}

function getCardBorderPath(race: Race | null): string {
  if (race === "Orc") return "./buttons/esc/orc/orc-options-menu-border.blp";
  if (race === "NightElf")
    return "./buttons/esc/nightelf/nightelf-options-menu-border.blp";
  if (race === "Undead")
    return "./buttons/esc/undead/undead-options-menu-border.blp";
  return "./buttons/esc/human/human-options-menu-border.blp";
}

function useCardBorderImage(race: Race | null): string {
  const [borderImageUrl, setBorderImageUrl] = useState("");

  useEffect(() => {
    let cancelled = false;
    const path = getCardBorderPath(race);
    void loadBlpDataUrl(path)
      .then((url) => loadDataUrlImage(url))
      .then((img) => {
        if (cancelled) return;
        setBorderImageUrl(composeBorderImageFromAtlas(img));
      })
      .catch((err) => console.error(err));
    return () => {
      cancelled = true;
    };
  }, [race]);

  return borderImageUrl;
}

function useSupplyIcon(): string {
  const [url, setUrl] = useState("");
  useEffect(() => {
    void loadBlpDataUrl("./resources/ResourceSupply.blp").then(setUrl);
  }, []);
  return url;
}

const DIFFICULTY_CLASS: Record<string, string> = {
  Beginner: "build-card-difficulty--beginner",
  Intermediate: "build-card-difficulty--intermediate",
  Advanced: "build-card-difficulty--advanced",
};

const HERO_ICONS: Record<string, string> = {
  Archmage: "BTNHeroArchMage",
  Blademaster: "BTNHeroBlademaster",
  "Blood Mage": "BTNHeroBloodElfPrince",
  "Crypt Lord": "BTNHeroCryptLord",
  "Death Knight": "BTNHeroDeathKnight",
  "Demon Hunter": "BTNHeroDemonHunter",
  "Far Seer": "BTNHeroFarseer",
  "Keeper of the Grove": "BTNKeeperOfTheGrove",
  Lich: "BTNHeroLich",
  "Mountain King": "BTNHeroMountainKing",
  Paladin: "BTNHeroPaladin",
  "Priestess of the Moon": "BTNPriestessOfTheMoon",
  "Shadow Hunter": "BTNShadowHunter",
  "Tauren Chieftain": "BTNHeroTaurenChieftain",
  Warden: "BTNHeroWarden",
};

function HeroIcon({ heroName }: { heroName: string }) {
  const [iconUrl, setIconUrl] = useState("");
  useEffect(() => {
    let cancelled = false;
    const file = HERO_ICONS[heroName];
    if (!file) return;
    void loadBlpDataUrl(`./buttons/command/${file}.blp`).then((url) => {
      if (!cancelled) setIconUrl(url);
    });
    return () => { cancelled = true; };
  }, [heroName]);
  if (!iconUrl) return null;
  return (
    <img src={iconUrl} alt={heroName} title={heroName} className="build-card-hero-icon" />
  );
}

import type { SkillPick } from "../../data/buildOrders";

const FALLBACK_SKILL_ICON = "./buttons/command/BTNSkillz.blp";

function HeaderSkillIcon({ pick }: { pick: SkillPick }) {
  const [iconUrl, setIconUrl] = useState("");
  const [hovered, setHovered] = useState(false);

  useEffect(() => {
    let cancelled = false;
    async function load() {
      try {
        const url = await loadBlpDataUrl(resolveIconPath(pick));
        if (!cancelled) setIconUrl(url);
      } catch {
        try {
          const url = await loadBlpDataUrl(FALLBACK_SKILL_ICON);
          if (!cancelled) setIconUrl(url);
        } catch {
          /* ignore */
        }
      }
    }
    void load();
    return () => { cancelled = true; };
  }, [pick.skill, pick.icon]);

  return (
    <div
      className="header-skill-icon-wrap"
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => setHovered(false)}
    >
      <span className="header-skill-level">Lv{pick.level}</span>
      {iconUrl
        ? <img src={iconUrl} alt={pick.skill} className="header-skill-icon" />
        : <div className="header-skill-icon header-skill-icon--placeholder" />
      }
      {hovered && <SkillTooltip pick={pick} />}
    </div>
  );
}

function HeaderSkillBar({ skillOrder }: { skillOrder: SkillPick[] }) {
  if (!skillOrder.length) return null;
  return (
    <div className="build-card-header-skills">
      <span className="build-card-header-skills-label">Skill Order</span>
      <div className="build-card-header-skills-row">
        {skillOrder.map((pick, i) => (
          <HeaderSkillIcon key={`${pick.skill}-${i}`} pick={pick} />
        ))}
      </div>
    </div>
  );
}

interface BuildCardProps {
  build: BuildOrder;
  elapsed: number;
  running: boolean;
  borderImageUrl: string;
}

function BuildCard({
  build,
  elapsed,
  running,
  borderImageUrl,
}: BuildCardProps) {
  const tableRef = useRef<HTMLDivElement>(null);
  const [scrollPct, setScrollPct] = useState(0);
  const scrollingFromBar = useRef(false);
  const supplyIconUrl = useSupplyIcon();

  const activeStepIndex = (() => {
    let idx = -1;
    for (let i = 0; i < build.steps.length; i++) {
      if (parseStepTime(build.steps[i].time) <= elapsed) idx = i;
    }
    return idx;
  })();

  // Sync native scroll → scrollbar percentage
  useEffect(() => {
    const el = tableRef.current;
    if (!el) return;
    const handler = () => {
      if (scrollingFromBar.current) return;
      const maxScroll = el.scrollHeight - el.clientHeight;
      if (maxScroll <= 0) {
        setScrollPct(0);
        return;
      }
      setScrollPct((el.scrollTop / maxScroll) * 100);
    };
    el.addEventListener("scroll", handler, { passive: true });
    return () => el.removeEventListener("scroll", handler);
  }, []);

  // Scrollbar → native scroll
  const handleScrollbarChange = useCallback((pct: number) => {
    setScrollPct(pct);
    const el = tableRef.current;
    if (!el) return;
    const maxScroll = el.scrollHeight - el.clientHeight;
    if (maxScroll <= 0) return;
    scrollingFromBar.current = true;
    el.scrollTop = (pct / 100) * maxScroll;
    requestAnimationFrame(() => {
      scrollingFromBar.current = false;
    });
  }, []);

  // Auto-scroll the active step into view
  useEffect(() => {
    if (activeStepIndex < 0 || !tableRef.current) return;
    const row = tableRef.current.querySelectorAll(".build-step-row")[
      activeStepIndex
    ] as HTMLElement | undefined;
    if (row) {
      row.scrollIntoView({ block: "nearest", behavior: "smooth" });
    }
  }, [activeStepIndex]);

  // border-image applied only to the active row; all rows already reserve
  // 6px transparent border space in CSS so nothing shifts.
  const activeBorderStyle: React.CSSProperties | undefined = borderImageUrl
    ? {
        borderImageSource: `url("${borderImageUrl}")`,
        borderImageSlice: 64,
        borderImageWidth: 1,
        borderImageRepeat: "round",
      }
    : undefined;

  return (
    <div className="build-card">

      {/* ── Full-width header banner ── */}
      <div className="build-card-header">
        {build.heroes?.[0] && (
          <div className="build-card-hero-col">
            <HeroIcon heroName={build.heroes[0]} />
            <span className="build-card-hero-name">{build.heroes[0]}</span>
          </div>
        )}
        <div className="build-card-header-main">
          <h4 className="build-card-title">{build.name}</h4>
          <div className="build-card-badges">
            {build.vs && (
              <span className="build-card-matchup">vs {build.vs}</span>
            )}
            {build.difficulty && (
              <span
                className={`build-card-difficulty ${DIFFICULTY_CLASS[build.difficulty] ?? ""}`}
              >
                {build.difficulty}
              </span>
            )}
          </div>
        </div>

        {build.skillOrder && build.skillOrder.length > 0 && (
          <HeaderSkillBar skillOrder={build.skillOrder} />
        )}

        {/* Timer — right-most element in header */}
        <div className="build-card-timer">
          <span className="build-card-elapsed">{formatTime(elapsed)}</span>
          <div className="build-card-controls">
            <GlueSmallButton onClick={running ? pauseTimer : startTimer}>
              {running ? "Pause" : "Start"}
            </GlueSmallButton>
            <GlueSmallButton
              onClick={resetTimer}
              disabled={elapsed === 0 && !running}
            >
              Reset
            </GlueSmallButton>
          </div>
        </div>
      </div>

      {/* Steps — full width */}
      <div className="build-card-steps-wrapper">
        <div className="build-card-steps" ref={tableRef}>
          <table className="build-steps-table">
            <thead>
              <tr>
                <th>#</th>
