  text-shadow: 1px 1px 0 rgba(0, 0, 0, 0.92);
  will-change: transform;
}

.esc-textarea-content > div {
  height: 18px;
}

.esc-textarea-scroll {
  position: relative;
  flex: 0 0 20px;
  width: 20px;
  height: 150px;
}

.esc-textarea-scroll-canvas {
  position: absolute;
  inset: 8px 0;
  width: 100%;
  height: calc(100% - 16px);
  display: block;
  image-rendering: pixelated;
  pointer-events: none;
}

.esc-textarea-scroll-thumb {
  position: absolute;
  top: 18%;
  left: 50%;
  width: 18px;
  height: 18px;
  transform: translate(-50%, -50%);
  background-repeat: no-repeat;
  background-size: 100% 100%;
  image-rendering: pixelated;
  pointer-events: none;
}

.esc-textarea-scroll input[type="range"] {
  position: absolute;
  inset: 8px 0;
  margin: 0;
  opacity: 0;
  writing-mode: vertical-lr;
  cursor: pointer;
}

.wc3-listbox-demo {
  display: flex;
  align-items: stretch;
  gap: 8px;
}

.wc3-listbox-shell {
  position: relative;
  width: 248px;
  height: 136px;
  overflow: hidden;
}

.wc3-listbox-canvas {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  display: block;
  image-rendering: pixelated;
  pointer-events: none;
}

.wc3-listbox-mask {
  position: absolute;
  inset: 16px;
  overflow: hidden;
  z-index: 2;
}

.wc3-listbox-items {
  position: absolute;
  inset: 0;
  padding: 2px 0;
  z-index: 2;
  text-align: left;
  will-change: transform;
}

.wc3-listbox-item {
  display: block;
  width: 100%;
  height: 20px;
  border: none;
  padding: 0 12px;
  background: transparent;
  color: #dbe4ff;
  font-family: inherit;
  font-size: 0.82rem;
  text-align: left;
  text-shadow: 1px 1px 0 rgba(0, 0, 0, 0.95);
  cursor: pointer;
}

.wc3-listbox-item:hover {
  color: var(--wc3-gold);
  background: rgba(255, 255, 255, 0.08);
}

.wc3-listbox-item--selected {
  color: var(--wc3-gold);
  background: rgba(255, 255, 255, 0.12);
}

.wc3-listbox-scrollbar {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 4px;
}

.wc3-listbox-scroll-arrow {
  width: 16px;
  height: 16px;
  border: none;
  background: transparent;
  padding: 0;
  cursor: pointer;
}

.wc3-listbox-scroll-arrow img {
  width: 100%;
  height: 100%;
  display: block;
  image-rendering: pixelated;
  pointer-events: none;
}

.wc3-listbox-scroll {
  position: relative;
  width: 18px;
  height: 96px;
}

.wc3-listbox-scroll-canvas {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  display: block;
  image-rendering: pixelated;
  pointer-events: none;
}

.wc3-listbox-scroll-thumb {
  position: absolute;
  left: 50%;
  width: 16px;
  height: 16px;
  transform: translate(-50%, -50%);
  background-repeat: no-repeat;
  background-size: 100% 100%;
  image-rendering: pixelated;
  pointer-events: none;
}

.wc3-listbox-scroll input[type="range"] {
  position: absolute;
  inset: 0;
  margin: 0;
  opacity: 0;
  writing-mode: vertical-lr;
  cursor: pointer;
}

.wc3-bar {
  position: relative;
  width: 100%;
  margin: 0 auto;
  overflow: hidden;
}

.wc3-bar + .wc3-bar {
  margin-top: 8px;
}

.wc3-bar--large {
  height: 20px;
}

.wc3-bar--unit {
  width: min(
    100%,
    182.93px
  ); /* HPBarConsoleSmall/ManaBarConsoleSmall frame ratio: 0.04065 / 0.004 */
  height: 18px;
}

.wc3-bar--compact {
  width: min(
    100%,
    157.14px
  ); /* XpBarConsole/TimerBar frame ratio: 0.17776 / 0.01810 */
  height: 16px;
}

.wc3-bar--build {
  width: min(
    100%,
    163.7px
  ); /* BuildProgressBar frame ratio: 0.10538 / 0.01030 */
}

.wc3-bar-track,
.wc3-bar-border {
  position: absolute;
  inset: 0;
  background-repeat: no-repeat;
  background-size: 100% 100%;
  image-rendering: auto;
  pointer-events: none;
}

.wc3-bar-canvas {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  display: block;
  image-rendering: auto;
  pointer-events: none;
}

.wc3-bar-fill-wrap {
  position: absolute;
  inset: 0 auto 0 0;
  overflow: hidden;
  transition: width 620ms ease;
}

.wc3-bar-fill,
.wc3-bar-highlight {
  position: absolute;
  inset: 0;
  background-repeat: no-repeat;
  background-size: 100% 100%;
  image-rendering: auto;
  pointer-events: none;
}

.wc3-bar-fill--health {
  filter: saturate(1.18);
}

.wc3-bar-fill--mana {
  filter: saturate(1.2) hue-rotate(6deg);
}

.wc3-bar-fill--progress {
  filter: saturate(1.05);
}

.wc3-bar-fill--build {
  filter: saturate(1.12) hue-rotate(-9deg);
}

.wc3-bar-highlight {
  mix-blend-mode: screen;
  opacity: 0.62;
}

.wc3-bar-segments {
  position: absolute;
  inset: 2px;
  pointer-events: none;
  background-image: repeating-linear-gradient(
    to right,
    rgba(0, 0, 0, 0.38) 0 1px,
    rgba(0, 0, 0, 0) 1px 10%
  );
  opacity: 0.55;
}

.wc3-bar-text {
  position: absolute;
  inset: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  color: #f6f8ff;
  font-size: 0.74rem;
  line-height: 1;
  text-shadow: 1px 1px 0 rgba(0, 0, 0, 0.95);
  pointer-events: none;
}

.wc3-bar--compact .wc3-bar-text {
  font-size: 0.68rem;
}

.loading-preview {
  display: flex;
  justify-content: center;
}

.loading-bar-composite {
  position: relative;
  width: min(100%, 640px);
  aspect-ratio: 8.007 / 1; /* LoadBar.mdx border geoset ratio: 0.45804 / 0.05720 */
  height: auto;
  max-height: 80px;
  overflow: visible;
}

.loading-bar-composite .lb-track {
  position: absolute;
  overflow: hidden;
}

.loading-bar-composite .lb-bg {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  background-repeat: repeat-x;
  background-size: auto 100%;
  image-rendering: auto;
}

.loading-bar-composite .lb-fill {
  position: absolute;
  left: 0;
  top: 0;
  bottom: 0;
  width: 0%;
  background-repeat: repeat-x;
  background-size: auto 100%;
  image-rendering: auto;
  transition: width 90ms linear;
  will-change: width;
}

.loading-bar-composite .lb-border,
.loading-bar-composite .lb-glass {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  display: block;
  object-fit: fill;
  pointer-events: none;
}

.loading-bar-composite .lb-border {
  z-index: 1;
}

.loading-bar-composite .lb-glass {
  z-index: 2;
  opacity: 1;
}

.loading-bar-composite .lb-glow {
  position: absolute;
  display: block;
  object-fit: fill;
  z-index: 4;
  mix-blend-mode: screen;
  mix-blend-mode: plus-lighter;
  pointer-events: none;
  transition:
    width 90ms linear,
    opacity 90ms linear;
}

.loading-bar-composite .lb-text {
  position: absolute;
  inset: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 5;
  color: #f6f8ff;
  font-size: 0.78rem;
  line-height: 1;
  text-shadow: 1px 1px 0 rgba(0, 0, 0, 0.95);
  pointer-events: none;
}

.esc-slider-demo {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 6px;
}

.esc-slider-value {
  color: #d8def5;
  font-size: 0.82rem;
}

.esc-slider-track {
  position: relative;
  width: 220px;
  height: 20px;
}

.esc-slider-canvas {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  display: block;
  image-rendering: pixelated;
  pointer-events: none;
}

.esc-slider-knob {
  position: absolute;
  top: 50%;
  width: 28px;
  height: 28px;
  transform: translate(-50%, -50%);
  background-repeat: no-repeat;
  background-size: 100% 100%;
  image-rendering: pixelated;
  pointer-events: none;
}

.esc-slider-track input[type="range"] {
  position: absolute;
  inset: 0;
  opacity: 0;
  margin: 0;
  cursor: pointer;
}

.cmd-overlay-button {
  position: relative;
  width: 48px;
  height: 48px;
  border: 2px solid #1a1a2e;
  border-radius: 2px;
  overflow: hidden;
  background: #000;
}

.cmd-overlay-button--showcase {
  width: 64px;
  height: 64px;
}

.cmd-overlay-base,
.cmd-overlay-layer,
.cmd-overlay-level {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  display: block;
  image-rendering: pixelated;
  pointer-events: none;
}

.cmd-overlay-add {
  mix-blend-mode: screen;
}

/* Loading Screen */
.loading-screen {
  position: fixed;
  inset: 0;
  z-index: 1000;
  display: flex;
  align-items: center;
  justify-content: center;
  background: #05080f;
  transition: opacity 400ms ease;
}

.loading-screen--fading {
  opacity: 0;
  pointer-events: none;
}

.loading-screen-bg {
  position: absolute;
  inset: 0;
  /* Placeholder gradient — swap for a WC3 loading screen image later:
     background: url("/loading/loading-screen-bg.jpg") center / cover no-repeat; */
  background: radial-gradient(
    ellipse at 50% 40%,
    #1a2440 0%,
    #0a0e1a 70%,
    #05080f 100%
  );
}

.loading-screen-content {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 24px;
  width: min(560px, 90vw);
}

.loading-screen-logo {
  width: min(340px, 70vw);
  height: auto;
  filter: drop-shadow(0 2px 12px rgba(0, 0, 0, 0.8));
  user-select: none;
  -webkit-user-drag: none;
}

.loading-screen-bar-wrap {
  width: 100%;
}

.loading-screen-label {
  margin: 0;
  color: #7c8fb5;
  font-size: 0.82rem;
  letter-spacing: 0.08em;
  text-transform: uppercase;
}

/* Hero Section */
.hero-section {
  text-align: center;
  padding: 24px 24px 32px;
  margin-bottom: 24px;
}

.hero-content {
  position: relative;
}

.hero-logo {
  display: block;
  margin: 0 auto 8px;
  width: min(420px, 60vw);
  height: auto;
  filter: drop-shadow(0 2px 6px rgba(0, 0, 0, 0.6));
  user-select: none;
  -webkit-user-drag: none;
}

.hero-subtitle {
  margin: 0 0 12px;
  color: #d3ddfb;
  font-size: 1.3rem;
}

.hero-description {
  margin: 0 0 24px;
  color: #9aa4c0;
  font-size: 0.95rem;
  line-height: 1.5;
  max-width: 600px;
  margin-left: auto;
  margin-right: auto;
}

.hero-description strong {
  color: #eceff7;
}

.hero-cta-row {
  display: flex;
  gap: 12px;
  justify-content: center;
  margin-bottom: 16px;
}

.hero-cta-row--components {
  align-items: center;
  flex-wrap: wrap;
  gap: 6px;
}

.home-cta-row {
  display: flex;
  gap: 16px;
  justify-content: center;
  margin-bottom: 16px;
}

.home-cta-row .esc-option-preview {
  width: 170px;
  height: 44px;
}

.hero-get-started-btn {
  width: 150px;
  height: 40px;
  flex: 0 0 150px;
  margin: 0;
}

.hero-install-editbox {
  width: 150px;
  height: 40px;
  flex: 0 0 150px;
  margin: 0;
  cursor: pointer;
}

.hero-install-editbox input {
  text-align: center;
  color: var(--wc3-gold);
  font-family:
    "Friz Quadrata", "Palatino Linotype", "Book Antiqua", Palatino, serif;
  font-size: 0.9rem;
  line-height: 1;
  cursor: pointer;
  padding: 0 8px;
}

.hero-footer {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 8px;
  margin-top: 4px;
}

.hero-footer-divider {
  width: 120px;
  height: 1px;
  background: linear-gradient(
    90deg,
    transparent 0%,
    var(--wc3-gold, #c6a44e) 50%,
    transparent 100%
  );
  opacity: 0.4;
}

.hero-footer-quote {
  margin: 0;
  color: #8a94b8;
  font-size: 0.86rem;
  font-style: italic;
  font-family:
    "Friz Quadrata", "Palatino Linotype", "Book Antiqua", Palatino, serif;
  text-shadow: 1px 1px 0 rgba(0, 0, 0, 0.7);
}

.hero-footer-version {
  color: #4e5678;
  font-size: 0.72rem;
  letter-spacing: 0.08em;
  text-transform: uppercase;
}

.hero-features {
  display: flex;
  gap: 12px;
  justify-content: center;
  margin: 0 0 20px;
  flex-wrap: wrap;
}

.hero-feature-tile {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 2px;
  background: rgba(20, 28, 50, 0.7);
  border: 1px solid #2b3a60;
  border-radius: 4px;
  padding: 10px 20px;
  min-width: 90px;
}

.hero-feature-value {
  color: var(--wc3-gold);
  font-size: 1.4rem;
  font-family:
    "Friz Quadrata", "Palatino Linotype", "Book Antiqua", Palatino, serif;
  line-height: 1;
}

.hero-feature-label {
  color: #7c8fb5;
  font-size: 0.74rem;
  text-transform: uppercase;
  letter-spacing: 0.06em;
}

.hero-races {
  display: flex;
  gap: 10px;
  justify-content: center;
  margin: 0 0 20px;
  flex-wrap: wrap;
}

.hero-race-badge {
  display: flex;
  align-items: center;
  gap: 6px;
  background: rgba(15, 22, 42, 0.75);
  border: 1px solid #243050;
  border-radius: 3px;
  padding: 5px 12px;
  color: #b8c8e8;
  font-size: 0.82rem;
}

.hero-race-badge-icon {
  width: 20px;
  height: 20px;
  object-fit: contain;
  image-rendering: pixelated;
}

/* Faction Preview */
.faction-preview-section .section-desc {
  text-align: center;
  font-style: italic;
}

.faction-preview {
  display: grid;
  grid-template-columns: repeat(4, minmax(0, 1fr));
  gap: 10px;
}

.faction-preview-card {
  background: transparent;
  border: none;
  border-radius: 0;
  padding: 0;
  text-align: left;
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.faction-preview-label {
  color: var(--wc3-dark-gold);
  font-size: 0.85rem;
  margin-bottom: 2px;
  text-align: center;
}

.faction-preview-samples {
  display: flex;
  flex-direction: column;
  gap: 6px;
  align-items: center;
}

.faction-preview-control {
  width: min(100%, 192px);
  max-width: 192px;
}

.faction-preview-control-label {
  margin: 0 0 4px;
  color: #7982a0;
  font-size: 0.64rem;
  letter-spacing: 0.06em;
  text-transform: uppercase;
}

.faction-preview-option-button {
  width: 192px;
  height: 36px;
}

.faction-preview-slider-demo {
  align-items: flex-start;
  gap: 3px;
}

.faction-preview-slider-track {
  width: 192px;
}

@media (max-width: 980px) {
  .faction-preview {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }
}

@media (max-width: 640px) {
  .button-preview-col--textarea {
    width: 100%;
  }

  .faction-preview {
    grid-template-columns: 1fr;
  }
}

/* Install Section */
.install-section .code-block {
  margin-bottom: 12px;
}

.code-block {
  background: #0a0a14;
  border: 1px solid #222233;
  border-radius: 6px;
  padding: 14px 18px;
  overflow-x: auto;
}

.code-block code,
.code-block pre {
  margin: 0;
  font-family:
    "Friz Quadrata", "Palatino Linotype", "Book Antiqua", Palatino, serif;
  font-size: 0.88rem;
  color: #c8d0e8;
  white-space: pre;
}

.install-note {
  margin: 16px 0 0;
  padding: 10px 16px;
  border-left: 3px solid var(--wc3-dark-gold);
  color: #9aa4c0;
  font-size: 0.88rem;
  line-height: 1.5;
}

.install-note code {
  color: var(--wc3-gold);
}

/* Design Tokens */
.token-grid {
  display: flex;
  flex-direction: column;
  gap: 6px;
  margin-top: 14px;
}

.token-grid-header {
  display: grid;
  grid-template-columns: 164px repeat(4, 1fr);
  gap: 6px;
  margin-bottom: 4px;
}

.token-faction-label {
  text-align: center;
  color: #7b818d;
  font-size: 0.72rem;
  text-transform: uppercase;
  letter-spacing: 0.04em;
}

.token-grid-row {
  display: grid;
  grid-template-columns: 164px repeat(4, 1fr);
  gap: 6px;
  align-items: center;
}

.token-name {
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.token-name code {
  color: var(--wc3-gold);
  font-size: 0.72rem;
}

.token-label {
  color: #5a6080;
  font-size: 0.66rem;
}

.token-swatch {
  position: relative;
  width: 100%;
  min-height: 44px;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 0;
  overflow: hidden;
}

.token-swatch--editbox-canvas {
  background: transparent;
}

.token-swatch-canvas {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  display: block;
  image-rendering: pixelated;
  pointer-events: none;
}

.token-hex {
  position: relative;
  z-index: 1;
  width: 100%;
  display: block;
  text-align: center;
  font-family:
    "Friz Quadrata", "Palatino Linotype", "Book Antiqua", Palatino, serif;
  font-size: 0.86rem;
  line-height: 1.1;
  letter-spacing: 0.02em;
  color: var(--token-hex-color);
  text-shadow: 1px 1px 0 rgba(0, 0, 0, 0.72);
}

.token-caption {
  margin: 16px 0 0;
  color: #5a6080;
  font-size: 0.85rem;
  text-align: center;
}

/* Accessibility */
.a11y-checklist {
  display: flex;
  flex-wrap: wrap;
  gap: 8px 16px;
  margin-top: 14px;
}

.a11y-check-item {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  color: #c8d0e8;
  font-size: 0.88rem;
}

.a11y-check-icon {
  color: #58d869;
  font-size: 1rem;
}

/* Bundle Size Chart */
.bundle-chart {
  --bundle-bar-width: 164px;
  display: flex;
  flex-direction: column;
  gap: 8px;
  margin: 14px auto 0;
  width: fit-content;
  max-width: 100%;
}

.bundle-chart-row {
  display: grid;
  grid-template-columns: 130px var(--bundle-bar-width) 50px;
  gap: 10px;
  align-items: center;
}

.bundle-chart-label {
  color: #c8d0e8;
  font-size: 0.82rem;
  text-align: right;
}

.bundle-chart-bar-track {
  position: relative;
  height: 16px;
  width: var(--bundle-bar-width);
  background: #0a0a14;
  border-radius: 2px;
  overflow: hidden;
}

.bundle-chart-bar-canvas {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  display: block;
  image-rendering: auto;
  pointer-events: none;
}

.bundle-chart-size {
  color: #7b818d;
  font-size: 0.78rem;
  font-family:
    "Friz Quadrata", "Palatino Linotype", "Book Antiqua", Palatino, serif;
}

/* FAQ */
.faq-section h3 {
  margin-bottom: 14px;
}

.faq-list {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.faq-item {
  border-top: 1px solid rgba(88, 104, 158, 0.45);
  padding-top: 10px;
}

.faq-item:first-child {
  border-top: none;
  padding-top: 0;
}

.faq-question-heading {
  margin: 0 0 4px;
  color: #e2e9ff;
  font-size: 0.92rem;
  font-weight: 400;
}

.faq-answer-text {
  margin: 0;
  color: #9aa4c0;
  font-size: 0.88rem;
  line-height: 1.5;
}

/* Footer */
.site-footer {
  position: relative;
  isolation: isolate;
  overflow: visible;
  text-align: center;
  padding: 44px clamp(96px, 12vw, 150px) 36px;
  margin-top: 8px;
  border-top: 1px solid #1e1e30;
}

.footer-content {
  position: relative;
  z-index: 5;
}

.footer-worker-unit {
  position: absolute;
  bottom: calc(-44px - var(--footer-worker-y-offset, 0px));
  width: clamp(138px, 12.1vw, 186px);
  height: clamp(250px, 21vw, 332px);
  pointer-events: none;
  z-index: 20;
}

.footer-worker-unit--left {
  left: clamp(0px, 0.9vw, 18px);
}

.footer-worker-unit--right {
  right: clamp(0px, 0.9vw, 18px);
  transform: scaleX(-1);
}

.footer-links {
